-- Generated by scripts/import-sutras.mjs from /Users/ray.shao/Downloads/華圓覺苑網站/法寶略節

create table if not exists public.sutras (
  id bigint generated always as identity primary key,
  seq integer not null unique,
  title text not null,
  translator text,
  content text not null,
  status text not null default '草稿' check (status in ('草稿', '已發布')),
  created_at timestamptz not null default now()
);

create index if not exists sutras_status_seq_idx on public.sutras (status, seq);

alter table public.sutras enable row level security;

grant select on public.sutras to anon;
grant select, insert, update, delete on public.sutras to authenticated;
grant select, insert, update, delete on public.sutras to service_role;
grant usage, select on sequence public.sutras_id_seq to authenticated, service_role;

drop policy if exists "public read published sutras" on public.sutras;
create policy "public read published sutras"
  on public.sutras
  for select
  to anon
  using (status = '已發布');

drop policy if exists "admin full access sutras" on public.sutras;
create policy "admin full access sutras"
  on public.sutras
  for all
  to authenticated
  using (public.is_admin())
  with check (public.is_admin());

insert into public.sutras (seq, title, translator, content, status)
values
  (1, '大般若波羅蜜多經卷第五百七十四', '三藏法師玄奘奉　詔譯', '第七曼殊室利分之一
如是我聞：一時，薄伽梵在室羅筏住誓多林給孤獨園，與大苾芻眾百千人俱，皆阿羅漢，唯阿難陀猶居學地，舍利子等而為上首。復與菩薩摩訶薩眾十千人俱，皆不退轉功德甲冑而自莊嚴，慈氏菩薩、妙吉祥菩薩、無礙辯菩薩、不捨善軛菩薩而為上首。
曼殊室利童子菩薩明相現時出自住處，詣如來所，在外而立。具壽舍利子、大迦多衍那、大迦葉波、大採菽氏、滿慈子、執大藏，如是一切大聲聞僧，亦於此時各從住處，詣如來所，在外而立。
爾時，世尊知諸大眾皆來集已，從住處出，敷如常座結跏趺坐，告舍利子：「汝今何故於晨朝時在門外立？」
時，舍利子白言：「世尊！曼殊室利童子菩薩先來住此，我等後來。」
爾時，世尊知而故問曼殊室利言：「善男子！汝實先來至此住處，為欲觀禮親近佛耶？」
曼殊室利前白佛言：「如是！世尊！如是！善逝！何以故？我於如來觀禮親近甞無厭足，為欲利樂諸有情故實先來此。世尊！我今來至此處親近禮敬觀如來者，專為利樂一切有情，非為證得佛菩提故，非為樂觀如來身故，非為擾動真法界故，非為分別諸法性故，亦不為餘種種事故。我觀如來即真如相無動無作、無所分別無異分別、非即方處非離方處、非有非無、非常非斷、非即三世非離三世、無生無滅、無去無來、無染不染、無二不二，心言路絕。若以此等真如之相觀於如來，名真見佛，亦名禮敬親近如來，實於有情能為利樂。」
佛告曼殊室利童子：「汝作是觀為何所見？」
曼殊室利白言：「世尊！我作是觀都無所見，於諸法相亦無所取。」
佛言：「善哉！善哉！童子！汝能如是觀於如來，於一切法心無所取亦無不取，非集非散。」
時，舍利子謂曼殊室利言：「仁能如是親近禮敬觀於如來，甚為希有！雖常慈愍一切有情，而於有情都無所得；雖能化導一切有情令趣涅槃，而無所執；雖為利樂諸有情故擐大甲冑，而於其中不起積集、散壞方便。」
時，曼殊室利白舍利子言：「如是！如是！如尊所說，我為利樂諸有情故，擐大甲冑令趣涅槃，實於有情及涅槃界所化、所證無得無執。又，舍利子！非我實欲利樂有情擐大甲冑。所以者何？諸有情界無增無減。假使於此一佛土中，有如殑伽沙數諸佛，一一皆住爾所大劫，晝夜常說爾所法門，一一法門各能度脫爾所佛土諸有情類，悉皆令入無餘涅槃。如此佛土有如是事，餘十方面各如殑伽沙等世界亦復如是。雖有爾所諸佛世尊，經爾所時說爾所法，度脫爾所諸有情類，皆令證入無餘涅槃，而有情界亦無增減。何以故？以諸有情自性離故、無邊際故不可增減。」
舍利子言：「曼殊室利！若諸有情自性離故、無邊際故無增減者，何緣菩薩求大菩提欲為有情常說妙法？」
曼殊室利言：「舍利子！我說有情都不可得，何有菩薩求大菩提欲為有情常說妙法？何以故？舍利子！諸法畢竟不可得故。」
佛告曼殊室利童子：「若諸有情都不可得，云何施設諸有情界？」
曼殊室利白言：「世尊！有情界者但假施設。」
「曼殊室利！設有問汝：有情界者為有幾何？汝得彼問當云何答？」
「世尊！我當作如是答：如佛法數，彼界亦爾。」
「曼殊室利！設復問汝：有情界者其量云何？汝得彼問復云何答？」
「世尊！我當作如是答：有情界量如諸佛境。」
「曼殊室利！設有問言：諸有情界為何所屬？汝得彼問復云何答？」
「世尊！我當作如是答：彼界所屬如佛難思。」
「曼殊室利！設有問言：有情界者為何所住？汝得彼問復云何答？」
「世尊！我當作如是答：若離染際所應住法，即有情界所應住法。」
「曼殊室利！汝修般若波羅蜜多為何所住？」
「世尊！我修甚深般若波羅蜜多都無所住。」
「曼殊室利！無所住者云何能修甚深般若波羅蜜多？」
「世尊！我由無所住故能修般若波羅蜜多。」
「曼殊室利！汝修般若波羅蜜多，於善、於惡何增何減？」
「世尊！我修甚深般若波羅蜜多，於善、於惡無增無減。世尊！我修甚深般若波羅蜜多，於一切法亦無增減。世尊！般若波羅蜜多出現世間，不為增減一切法故。世尊！修學甚深般若波羅蜜多，不為棄捨異生等法，不為攝受一切佛法。所以者何？甚深般若波羅蜜多不為捨法、得法故起。世尊！修學甚深般若波羅蜜多，不為厭離生死過失，不為欣樂涅槃功德。所以者何？修此法者不見生死，況有厭離！不見涅槃，況有欣樂！世尊！修學甚深般若波羅蜜多，不見諸法有劣有勝、有失有得、可捨可取。世尊！修學甚深般若波羅蜜多，不得諸法可增可減。所以者何？非真法界有增有減。世尊！若能如是修者，名真修學甚深般若波羅蜜多。
「復次，世尊！若修般若波羅蜜多，於一切法不增不減，名真修學甚深般若波羅蜜多；若修般若波羅蜜多，於一切法不生不滅，名真修學甚深般若波羅蜜多；若修般若波羅蜜多，於一切法不見增減，名真修學甚深般若波羅蜜多；若修般若波羅蜜多，於一切法不見生滅，名真修學甚深般若波羅蜜多。
「復次，世尊！若修般若波羅蜜多，於一切法無所思惟，若多若少俱無希願，能、所希願及希願者皆不取著，名真修學甚深般若波羅蜜多；若修般若波羅蜜多，不見諸法有好有醜、有高有下，名真修學甚深般若波羅蜜多。
「復次，世尊！善男子等若修般若波羅蜜多，於諸法中不得勝劣，謂都不見此勝此劣，是真般若波羅蜜多。所以者何？真如、法界、法性、實際無勝無劣。若如是修，名真修學甚深般若波羅蜜多。」
佛告曼殊室利童子：「諸佛妙法豈亦不勝？」
曼殊室利白言：「世尊！諸佛妙法不可取故，亦不可言是勝是劣，如來豈不證諸法空？」
世尊答言：「如是！童子！」
曼殊室利復白佛言：「諸法空中何有勝劣？」
世尊讚曰：「善哉！善哉！如是！如是！如汝所說。曼殊室利！佛法豈不是無上耶？」
「如是！世尊！一切佛法雖實無上，而於其中無法可得，故不可說佛法無上。
「復次，世尊！善男子等若修般若波羅蜜多，不欲住持一切佛法，不欲調伏異生法等；甚深般若波羅蜜多，於諸佛法、異生法等，不欲增長及調伏故，於一切法無分別故。若如是修，名真修學甚深般若波羅蜜多。
「復次，世尊！善男子等若修般若波羅蜜多，不見諸法有可思惟、可分別者。」
「曼殊室利！汝於佛法豈不思惟？」
「不也！世尊！我若見有真實佛法應可思惟，然我不見。
「世尊！般若波羅蜜多不為分別諸法故起，謂不分別是異生法、是聲聞法、是獨覺法、是菩薩法、是如來法。善男子等精勤修學甚深般若波羅蜜多，於諸法中都無所得亦無所說，謂不說有異生法性，亦不說有聲聞乃至如來法性。所以者何？此諸法性皆畢竟空、不可見故。若如是修，名真修學甚深般若波羅蜜多。
「復次，世尊！善男子等勤修般若波羅蜜多，不作是念：『此是欲界，此是色界，此無色界，此是滅界。』所以者何？甚深般若波羅蜜多不見有法是可滅者。若如是修，名真修學甚深般若波羅蜜多。
「復次，世尊！若修般若波羅蜜多，於一切法不作恩怨。何以故？甚深般若波羅蜜多不為住持一切佛法，不為棄捨異生等法。所以者何？善男子等勤修般若波羅蜜多，於佛法中不欲證得、不欲滅壞異生等法，達一切法性平等故。若如是修，名真修學甚深般若波羅蜜多。」
爾時，世尊即便讚曰：「曼殊室利！善哉！善哉！汝今乃能說甚深法，與諸菩薩摩訶薩眾作真法印，亦與聲聞及獨覺等增上慢者作大法印，令如實知先所通達非真究竟。曼殊室利！若善男子、善女人等聞是深法，心不沈沒亦不驚怖，當知是人非於一佛乃至千佛種諸善根，定於無量無邊佛所種諸善根，乃能聞是甚深般若波羅蜜多，心不沈沒亦不驚怖。」
爾時，曼殊室利童子合掌恭敬，復白佛言：「我欲更說甚深般若波羅蜜多，唯願開許！」
佛告曼殊室利童子：「汝欲說者，隨汝意說。」
曼殊室利便白佛言：「世尊！若修甚深般若波羅蜜多，於法不得是可住者，亦復不得是不可住，當知如是甚深般若波羅蜜多不緣法住。何以故？以一切法無所緣故。世尊！若能如是修者，名真修學甚深般若波羅蜜多，於一切法不取相故。
「復次，世尊！應觀如是甚深般若波羅蜜多，不現前觀諸法性相，謂於佛法尚不現觀，況菩薩法！於菩薩法尚不現觀，況獨覺法！於獨覺法尚不現觀，況聲聞法！於聲聞法尚不現觀，況異生法！何以故？以一切法性相離故。
「復次，世尊！依修如是甚深般若波羅蜜多，於諸法中無所分別，謂不分別是可思議、不可思議法性差別，當知菩薩摩訶薩眾修行般若波羅蜜多，於諸法中都無分別。
「復次，世尊！依修如是甚深般若波羅蜜多，一切法中都不見有此是佛法、此非佛法，此可思議、此不可思議，以一切法無差別性故。若諸有情能修如是甚深般若波羅蜜多，觀一切法皆是佛法，順菩提故；觀一切法皆不思議，畢竟空故，是諸有情已曾親近、供養恭敬多百千佛種諸善根，乃能如是修行般若波羅蜜多。
「復次，世尊！若善男子、善女人等，聞說如是甚深般若波羅蜜多，心不沈沒亦不驚怖，當知過去已曾親近、供養恭敬多百千佛種諸善根乃能如是。
「復次，世尊！應觀如是甚深般若波羅蜜多，若能勤修，則於諸法不見雜染不見清淨；雖無所見，而能勤修甚深般若波羅蜜多，於一切時心無厭倦。
「復次，世尊！若修如是甚深般若波羅蜜多，於諸異生、聲聞、獨覺、菩薩、佛法無差別想，了此等法畢竟空故。若能如是，名真修學甚深般若波羅蜜多。」
佛告曼殊室利童子：「汝已親近、供養幾佛？」
曼殊室利白言：「世尊！我已親近、供養佛數量同幻士心、心所法，以一切法皆如幻故。」
「曼殊室利！汝於佛法豈不趣求？」
「世尊！我今不見有法非佛法者，何所趣求？」
「曼殊室利！汝於佛法已成就耶？」
「世尊！我今都不見法可名佛法，何所成就？」
「曼殊室利！汝豈不得無著性耶？」
「世尊！我今即無著性，豈無著性復得無著？」
「曼殊室利！汝不當坐菩提座耶？」
「世尊！諸佛於菩提座尚無坐義，況我能坐！何以故？以一切法皆用實際為定量故，於實際中坐及坐者俱不可得。」
「曼殊室利！言實際者，是何增語？」
「世尊！實際當知即是偽身增語。」
「曼殊室利！云何偽身可名實際？」
「世尊！實際無去無來、非真非偽，身非身相俱不可得，偽身亦爾，是故偽身即是實際。」
時，舍利子便白佛言：「若諸菩薩聞說如是甚深般若波羅蜜多，心不沈沒亦不驚怖，是諸菩薩定趣菩提不復退轉。」
慈氏菩薩復白佛言：「若諸菩薩聞說如是甚深般若波羅蜜多，心不沈沒亦不驚怖，是諸菩薩已近無上正等菩提。何以故？是諸菩薩現覺法性離一切分別如大菩提故。」
曼殊室利亦白佛言：「若諸菩薩聞說如是甚深般若波羅蜜多，心不沈沒亦不驚怖，是諸菩薩如佛世尊堪受世間供養恭敬。何以故？於一切法覺實性故。」
時，有女人名無緣慮，合掌恭敬白言：「世尊！若諸有情聞說如是甚深般若波羅蜜多，心不沈沒亦不驚怖，是諸有情於異生法、若聲聞法、若獨覺法、若菩薩法、若如來法皆不緣慮。所以者何？達一切法都無所有，能、所緣慮俱不可得。」
爾時，佛告舍利子等：「如是！如是！如汝所說。若善男子、善女人等，聞說如是甚深般若波羅蜜多，心不沈沒亦不驚怖，是善男子、善女人等當知已住不退轉地，定趣菩提不復退轉。舍利子等！若諸有情聞說如是甚深般若波羅蜜多，心不沈沒亦不驚怖，歡喜、信樂、聽聞、受持，轉為他說心無厭倦；是諸有情能為一切真實廣大殊勝施主，能施一切無上財寶，具足布施波羅蜜多；是諸有情淨戒圓滿，具真淨戒、具勝淨戒，淨戒功德皆已圓滿，具足淨戒波羅蜜多；是諸有情安忍圓滿，具真安忍、具勝安忍，安忍功德皆已圓滿，具足安忍波羅蜜多；是諸有情精進圓滿，具真精進、具勝精進，精進功德皆已圓滿，具足精進波羅蜜多；是諸有情靜慮圓滿，具真靜慮、具勝靜慮，靜慮功德皆已圓滿，具足靜慮波羅蜜多；是諸有情般若圓滿，具真般若、具勝般若，般若功德皆已圓滿，具足般若波羅蜜多；是諸有情成就真勝慈、悲、喜、捨，亦能為他宣說、開示甚深般若波羅蜜多。」
佛告曼殊室利童子：「汝觀何義，欲證無上正等菩提？」
曼殊室利白言：「世尊！我於無上正等菩提尚無住心，況當欲證！我於菩提無求趣意。所以者何？菩提即我，我即菩提，如何求趣？」
佛言：「善哉！善哉！童子！汝能巧說甚深義處。汝於先佛多植善根，久發大願，能依無得修行種種清淨梵行。」
曼殊室利便白佛言：「若於諸法有所得者，可依無得修淨梵行。我都不見有法可得及無所得，如何可言能依無得修淨梵行？」
佛告曼殊室利童子：「汝今見我聲聞德耶？」
「世尊！我見！」
佛言：「童子！汝云何見？」
「世尊！今我見諸聲聞，非異生、非聖者，非有學、非無學，非可見、非不可見，非見者、非不見者，非多、非少，非小、非大，非已調伏、非未調伏，我如是見而無見想。」
時，舍利子便問彼言：「於聲聞乘既如是見，復云何見正等覺乘？」
「大德！我今不見菩薩，亦復不見諸菩薩法。不見菩提，亦復不見趣菩提法，亦不見有趣菩提行，亦不見有證菩提法，不見有能證菩提者。我如是見正等覺乘，謂於其中都無所見。」
時，舍利子復問彼言：「汝於如來當云何見？」
「大德！止！止！勿於如來大龍象王而興言論。」
「曼殊室利！所言佛者，是何增語？」
「今問大德：所言我者，復何增語？」
舍利子言：「我者但有假立名字，是空增語。」
「大德當知！佛之增語即我增語，我之與佛俱畢竟空，但隨世間假立名字。菩提名字亦是假立，不可尋此求實菩提，菩提相空不可表示。何以故？名字、菩提二俱空故。名字空故言說亦空，不可以空表示空法；菩提空故佛亦是空，故所言佛是空增語。
「復次，大德！所言佛者，無來無去、無生無滅，無所證得、無所成就，無名、無相不可分別，無言、無說不可表示，唯微妙智自內證知，謂諸如來覺一切法畢竟空寂證大菩提，隨順世間假立名字，故稱為佛非為實有，若有若無不可得故。
「復次，大德！如來所證微妙智慧說名菩提，成就菩提故名為佛；菩提空故佛亦是空，由此佛名是空增語。」
時，舍利子便白佛言：「曼殊室利所說深法，非初學者所能了知。」
爾時，曼殊室利童子即白具壽舍利子言：「我所說者，非唯初學不能解了，所作已辦阿羅漢等亦不能知，非我所說有能知者。所以者何？菩提之相非識所識，無見無聞、無得無念、無生無滅，不可說示、不可聽受。如是菩提性相空寂，諸大菩薩尚未能知，何況二乘所知解了！菩提性相尚不可得，況當有實證菩提者！」
舍利子言：「曼殊室利！佛於法界豈不證耶？」
「不也！大德！所以者何？佛即法界，法界即佛，法界不應還證法界。
「又，舍利子！一切法空說為法界，即此法界說為菩提，法界、菩提俱離性相，由斯故說一切法空。一切法空、菩提、法界，皆是佛境無二無別，無二無別故不可了知，不可了知故則無言說，無言說故不可施設有為無為、有非有等。
「又，舍利子！一切法性亦無二無別，無二無別故不可了知，不可了知故則無言說，無言說故不可施設。所以者何？諸法本性都無所有，不可施設在此在彼、此物彼物。
「又，舍利子！若造無間，當知即造不可思議亦造實際。何以故？舍利子！不可思議與五無間，俱即實際性無差別。既無有能造實際者，是故無間、不可思議亦不可造。由斯理趣，造無間者非墮地獄，不思議者非得生天；造無間者亦非長夜沈淪生死，不思議者亦非究竟能證涅槃。何以故？舍利子！不可思議與五無間皆住實際，性無差別，無生無滅、無去無來、非因非果、非善非惡、非招惡趣非感人天、非證涅槃非沒生死。何以故？以真法界非善非惡、非高非下，無前後故。
「又，舍利子！犯重苾芻非墮地獄，淨持戒者非得生天；犯重苾芻非沈生死，淨持戒者非證涅槃；犯重苾芻非應毀訾，淨持戒者非應讚歎；犯重苾芻非應輕蔑，淨持戒者非應恭敬；犯重苾芻非應乖諍，淨持戒者非應和合；犯重苾芻非應遠離，淨持戒者非應親近；犯重苾芻非應損減，淨持戒者非應增益；犯重苾芻非不應供，淨持戒者非定應供；犯重苾芻非增長漏，淨持戒者非損減漏；犯重苾芻非不清淨，淨持戒者非定清淨；犯重苾芻非無淨信，淨持戒者非有淨信；犯重苾芻非不應受清淨信施，淨持戒者非定應受清淨信施。何以故？舍利子！真法界中若持若犯其性平等，無差別故。
「又，舍利子！諸異生類名和合者，漏盡苾芻名不和合。」
「曼殊室利！汝依何義作如是說？」
「大德！異生與生因合，名和合者，諸阿羅漢無如是義，名不和合。我依此義作如是說。
「又，舍利子！諸異生類名超怖者，漏盡苾芻名不超怖。」
「曼殊室利！汝依何義作如是說？」
「大德！異生於可怖法不生怖畏，名超怖者，諸阿羅漢知可怖法實無所有、無怖可超。我依此義作如是說。
「又，舍利子！諸異生類得無滅忍，諸菩薩眾得無生忍。」
「曼殊室利！汝依何義作如是說？」
「大德！異生不樂寂滅，名得無滅忍，諸菩薩眾不見法生，名得無生忍。我依此義作如是說。
「又，舍利子！諸異生類名調伏者，漏盡苾芻名不調伏。」
「曼殊室利！汝依何義作如是說？」
「大德！異生未調伏故應可調伏，名調伏者，諸阿羅漢漏結已盡不復須調，名不調伏。我依此義作如是說。
「又，舍利子！諸異生類名增上心超越行者，漏盡苾芻名心下劣非超越行。」
「曼殊室利！汝依何義作如是說？」
「大德！異生其心高舉行違法界，名增上心超越行者，諸阿羅漢其心謙下行順法界，名心下劣非超越行。我依此義作如是說。」
時，舍利子讚曼殊室利言：「善哉！善哉！善能為我解密語義。」
曼殊室利報言：「如是！如是！大德！我非但能解密語義，我亦即是一切漏盡真阿羅漢。何以故？我於聲聞、獨覺樂欲皆永不起故，名漏盡真阿羅漢。」
佛告曼殊室利童子：「頗有因緣，可說菩薩坐菩提座不證無上正等菩提？」
曼殊室利白言：「世尊！亦有因緣，可說菩薩坐菩提座不證無上正等菩提，謂菩提中無有少法可名無上正等菩提，然真菩提性無差別，非坐可得、不坐便捨。由此因緣，可說菩薩坐菩提座不證菩提，無相菩提不可證故。」
曼殊室利復白佛言：「無上菩提即五無間，彼五無間即此菩提。所以者何？菩提、無間俱假施設，非真實有菩提之性，非可證得，非可修習，非可現見，彼五無間亦復如是。又一切法本性畢竟不可現見，於中無覺、無覺者，無見、無見者，無知、無知者，無分別、無分別者，離相平等名為菩提，五無間性亦復如是。由此菩提非可證得，言可證得、修習、現見大菩提者是增上慢。」
佛告曼殊室利童子：「汝今謂我是如來耶？」
「不也！世尊！不也！善逝！我不謂佛是實如來。所以者何？夫如來者以微妙智證會真如，妙智、真如二俱離相，真如離相非謂真如，妙智亦然非謂妙智，既無妙智及無真如，是故如來亦非真實。何以故？真如、妙智但假施設，如來亦爾，非二、不二。是故妙智、真如、如來，但有假名而無一實，故不謂佛是實如來。」
佛告曼殊室利童子：「汝非疑惑於如來耶？」
「不也！世尊！不也！善逝！何以故？我觀如來實不可得、無生無滅，故無所疑。」
佛告曼殊室利童子：「如來豈不出現世間？」
「不也！世尊！不也！善逝！若真法界出現世間，可言如來出現於世，非真法界出現世間，是故如來亦不出現。」
「曼殊室利！汝謂殑伽沙數諸佛入涅槃不？」
「世尊！豈不諸佛如來同不思議一境界相？」
「曼殊室利！如是！如是！如汝所說。諸佛如來同不思議一境界相。」
曼殊室利復白佛言：「今佛世尊現住世不？」
佛言：「如是！」
曼殊室利便白佛言：「若佛世尊現住世者，殑伽沙等諸佛世尊亦應住世。何以故？一切如來同不思議一境相故。不思議相無生無滅，如何諸佛有入涅槃？是故，世尊！若未來佛當有出世，一切如來皆當出世；若過去佛已入涅槃，一切如來皆已滅度；若現在佛現證菩提，一切如來皆應現證。何以故？不思議中去、來、現在所有諸佛無差別故。然諸世間迷謬執著種種戲論，謂佛世尊有生有滅，有證菩提。」
佛告曼殊室利童子：「汝所說法，唯有如來、不退菩薩、大阿羅漢所能解了，餘不能知。何以故？唯如來等聞是深法，如實了達不讚不毀，知心、非心不可得故。所以者何？一切法性皆悉平等，心及非心俱不可得，由此於法無讚無毀。」
曼殊室利即白佛言：「於是深法誰當讚毀？」
佛言：「童子！愚夫異生彼如是心非實心性，同佛心性不可思議。」
曼殊室利復白佛言：「愚夫異生心、非心性，同佛心性不思議耶？」
佛告曼殊室利童子：「如是！如是！如汝所說。何以故？佛、有情心及一切法，皆悉平等、不思議故。」
曼殊室利復白佛言：「佛、有情心及一切法，若皆平等、不可思議；今諸聖賢求涅槃者，勤行精進豈不唐捐？所以者何？不思議性與涅槃性既無差別，何用更求？若有說言此異生法、此聖者法有差別相，當知彼人未曾親近真淨善友，作如是說，令諸有情執二法異，沈淪生死不得涅槃。」
佛告曼殊室利童子：「汝願如來於有情類最為勝不？」
「世尊！若有真實有情，我願如來於彼最勝，然有情類實不可得。」
佛告曼殊室利童子：「汝願佛成就不思議法耶？」
「世尊！若有不思議法實可成就，我願如來成就彼法，然無是事。」
佛告曼殊室利童子：「汝願如來說法調伏弟子眾不？」
「世尊！若有說法調伏真如法界，我願如來說法調伏諸弟子眾，然佛世尊出現於世，於有情類都無恩德。所以者何？諸有情類皆住無雜真如法界，於此界中異生、聖者、能說、能受俱不可得。」
佛告曼殊室利童子：「汝願如來是世無上真福田不？」
曼殊室利白言：「世尊！若諸福田是實有者，我亦願佛於彼無上，然諸福田實不可得，是故諸佛皆非福田、非非福田，以福、非福及一切法性平等故。然世間田能無盡者，世共說彼名無上田，諸佛世尊證無盡福，是故可說無上福田。又世間田無轉變者，世共說彼名無上田，諸佛世尊證無變福，是故可說無上福田。又世間田用難思者，世共說彼名無上田，諸佛世尊證難思福，是故可說無上福田。諸佛福田雖實無上，而植福者無減無增。」
佛告曼殊室利童子：「汝依何義作如是說？」
曼殊室利白言：「世尊！佛福田相不可思議，若有於中而植福者，即便能了平等法性，達一切法無減無增，故佛福田最為無上。」
爾時，大地以佛世尊神力、法力六返變動。時，眾會中有十六億大苾芻眾，諸漏永盡心得解脫；七百苾芻尼、三千鄔波索迦、四萬鄔波斯迦、六十俱胝那庾多數欲界天眾，遠塵離垢生淨法眼。
時，阿難陀即從座起頂禮佛足，偏覆左肩，右膝著地，合掌恭敬白言：「世尊！何因何緣，今此大地六返變動？」
爾時，佛告阿難陀言：「由妙吉祥說福田相，我今印許故現斯瑞。過去諸佛亦於此處說福田相令大地動，故於今時現如是事。」', '已發布'),
  (2, '大般若波羅蜜多經卷第五百七十五', '三藏法師玄奘奉　詔譯', '第七曼殊室利分之二
爾時，舍利子白佛言：「世尊！曼殊室利不可思議。所以者何？曼殊室利所說法相不可思議。」
佛告曼殊室利童子：「汝之所說實難思議，誠如具壽舍利子說。」
曼殊室利即白佛言：「我所說法不可說可思議，亦不可說不可思議。所以者何？不可思議、可思議性俱無所有，但有音聲，一切音聲亦不可說不可思議、可思議性，以一切法自性離故。作是說者，乃名為說不可思議。」
佛告曼殊室利童子：「汝今現入不可思議三摩地耶？」
曼殊室利白言：「世尊！我不現入此三摩地。所以者何？我都不見此三摩地性異於我，不見有心能思惟我及此定故。不可思議三摩地者，心、非心性俱不能入，云何可言我入此定？
「復次，世尊！我昔初學作意現入此三摩地，非於今時復更作意現入此定。如善射夫初學射業，注心麁的方乃發箭，久習成就能射毛端，不復注心在彼麁的，隨所欲射發箭便中；如是我先初學定位，要先繫念在不思議，然後乃能現入此定，久習成就，於此定中不復繫心任運能住。所以者何？我於諸定已得善巧，任運入出不復作意。」
時，舍利子便白佛言：「觀此曼殊室利童子未可保信。所以者何？於此定中似不恒住，然無餘定微妙寂靜同此定者。」
曼殊室利便白具壽舍利子言：「大德！寧知更無餘定寂靜同此？」
舍利子言：「豈更有定寂靜同此？」
曼殊室利報言：「大德！若此可得，可言餘定寂靜同此，然不可得。」
舍利子言：「曼殊室利！豈今此定亦不可得？」
「大德！此定實不可得。所以者何？謂一切定，可思議者有相可得，不思議者無相可得，此定既曰不可思議，是故定應實不可得。又，舍利子！不思議定，一切有情無不得者。所以者何？一切心性皆離心性，離心性者皆即名為不思議定，故有情類無不得者。」
佛讚曼殊室利童子：「善哉！善哉！曼殊室利！汝於過去無量佛所多植善根、久發大願，所修梵行皆依無得，發言皆說甚深義處。曼殊室利！汝豈不以住深般若波羅蜜多能一切時說甚深義？」
曼殊室利即白佛言：「若我由住甚深般若波羅蜜多能如是說，便住我想及住有想能如是說，若住我想及住有想能如是說，則深般若波羅蜜多亦有所住，若深般若波羅蜜多有所住者，則深般若波羅蜜多亦以我想及以有想為所住處，然深般若波羅蜜多遠離二想、住無所住。如諸佛住微妙寂靜，無起、無作、無動、無轉以為所住；甚深般若波羅蜜多不住有法、不住無法，故此所住不可思議。甚深般若波羅蜜多於一切法皆不現行，甚深般若波羅蜜多當知即是不思議界，不思議界即是法界，法界即是不現行界，不現行界當知即是不思議界，不思議界當知即是甚深般若波羅蜜多。甚深般若波羅蜜多、我界、法界無二無別，無二無別即是法界，法界即是不現行界，不現行界當知即是甚深般若波羅蜜多，甚深般若波羅蜜多當知即是不思議界，不思議界當知即是不現行界，不現行界當知即是無所有界，無所有界當知即是無生滅界，無生滅界當知即是不思議界，不思議界與如來界、我界、法界無二無別。
「是故，世尊！若能如是修行般若波羅蜜多，於大菩提更不求證。何以故？甚深般若波羅蜜多即菩提故。世尊！若有實知我界即知無著，若知無著即知無法，若知無法即是佛智，佛智即是不思議智，當知佛智無法可知，名不知法。所以者何？此智自性都無所有，無所有法云何能於真法界轉？此智自性既無所有即無所著，若無所著即體非智，若體非智即無境界，若無境界即無所依，若無所依即無所住，若無所住即無生滅，若無生滅即不可得，若不可得即無所趣，既無所趣，此智不能作諸功德，亦復不能作非功德。所以者何？此無思慮我作功德、作非功德。無思慮智不可思議，不可思議即是佛智，是故此智於一切法無取不取，亦非前際中際後際、非先已生非先未生，無出無沒、非常非斷，更無餘智類此智者。由是此智不可思議，同於虛空不可比類，無此無彼、非好非醜；既無餘智類此可得，是故此智無等、不等，由此故名無等等智；又無餘智對此可得，是故此智無對、不對，由此故名無對對智。」
佛告曼殊室利童子：「如是妙智不可動耶？」
曼殊室利白言：「世尊！如是妙智性不可動。如鍛金師燒鍊金璞，既得精熟秤量無動；此智亦爾，久修成熟，無作無證、無生無盡、無起無沒，安固不動。」
佛告曼殊室利童子：「誰能信解如是妙智？」
曼殊室利白言：「世尊！若能不行般涅槃法，於生死法亦能不行，於薩迦耶行寂滅行，於般涅槃行無動行。不斷貪欲、瞋恚、愚癡，亦非不斷。所以者何？如是三毒自性遠離，非盡不盡於生死法不起不墮，於諸聖道不離不修。彼於此智能深信解。」
佛讚曼殊室利童子：「善哉！善哉！善說此事。」
爾時，具壽大迦葉波前白佛言：「當來之世，誰能於此法毘奈耶甚深義趣信解修學？」
佛告具壽大迦葉波：「今此會中苾芻等眾，當來之世，於此所說法毘奈耶甚深義趣，能生信解聽受修學，亦能為他演說流布。如大長者失無價珠，苦惱纏心愁憂不樂，後時還得踴躍歡喜。今此會中苾芻等眾亦復如是，聞深般若波羅蜜多，信解修學；後不聞說如是法門，苦惱纏心愁憂不樂，咸作是念：『我等何時當更得聞如是深法？』後時若得聞此法門，踊躍歡喜復作是念：『我今得聞如是經典，即為見佛親近供養。』如圓綵樹胞初出時，三十三天踊躍歡喜：『此樹不久花必開敷、香氣氛氳，我等遊集。』苾芻等眾亦復如是，聞深般若波羅蜜多，信受修行應生歡喜，一切佛法不久開敷。
「飲光當知！未來之世苾芻等眾若聞如是甚深般若波羅蜜多，信解修行心不沈沒，必於此會已得聽聞，歡喜受持、演說流布，當知彼類由聞是法，歡喜踊躍信受修行，不久開敷一切佛法。如來滅後，若有受持、演說、流布此經典者，當知皆是佛威神力之所加護令彼事成。
「飲光當知！若有聞是甚深般若波羅蜜多歡喜受持，彼於過去無量佛所多植善根，已得聽聞，非適今也！如穿珠者，忽然遇得無價末尼，生大歡喜，當知彼類曾見此珠，故生歡喜，非今創見。如是當來諸苾芻等，深心愛樂聽聞正法，忽遇般若波羅蜜多，歡喜聽聞、信受、修學，當知彼類已於往昔無量佛所曾聞是經，非於今時創聞能爾。
「飲光當知！若善男子、善女人等，聞妙吉祥所說般若波羅蜜多，歡喜踊躍、樂聞無厭，數復慇懃重請演說，是善男子、善女人等，過去已從曼殊室利聞說般若波羅蜜多歡喜受持、信解、修學，亦曾親近曼殊室利供養恭敬，故能如是。譬如有人遇入城邑，其中一切園林、池沼、舍宅、人物無不悉見；後至餘處，聞人讚說此城邑中所有勝事，深生歡喜請其重說，若更得聞倍復歡喜，彼由往昔皆曾見故。如是當來諸善男子、善女人等，聞妙吉祥所說般若波羅蜜多，歡喜樂聞甞無厭足，慇懃固請重說深義，聞已讚歎倍生歡喜，當知此等皆由往昔已曾親近曼殊室利，供養恭敬聽受斯法，故於今時能成是事。」
爾時，具壽大迦葉波便白佛言：「如來善說現在、當來善男子等聞深般若波羅蜜多，信解修行諸行、狀、相。」
佛言：「如是！如汝所說。我已善說彼行、狀、相。」
曼殊室利即白佛言：「現在、當來善男子等聞是深法諸行、狀、相，當知即非諸行、狀、相，以所聞法微妙寂靜，諸行、狀、相皆不可得，云何如來作如是說：我已善說彼行、狀、相？」
佛告曼殊室利童子：「如是！如是！如汝所說。現在、當來善男子等聞是深法諸行、狀、相，彼實皆非諸行、狀、相，以所聞法微妙寂靜，諸行、狀、相皆不可得。然彼聞說甚深法時，歡喜受持、信解、修學，必於過去已曾得聞歡喜受行，故能如是，此行、狀、相依世俗說，非勝義中有如是事。曼殊室利當知！顯了甚深般若波羅蜜多，即為顯了一切佛法，通達真實不思議事。曼殊室利！我本修學菩薩行時所集善根，皆由修學甚深般若波羅蜜多方得成滿。欲住菩薩不退轉地，欲證無上正等菩提，亦由修學甚深般若波羅蜜多乃得成辦。
「曼殊室利！若善男子、善女人等欲集菩薩所集善根，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等欲住菩薩不退轉地，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等欲證無上正等菩提，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等，欲善通達一切法界平等之相，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等，欲善了知一切有情心行平等，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等，欲疾證得一切佛法，當學如是甚深般若波羅蜜多。
「曼殊室利！若善男子、善女人等，欲知佛說如來不能現覺諸法祕密義趣，當學如是甚深般若波羅蜜多。何以故？所覺諸法及能覺者不可得故。曼殊室利！若善男子、善女人等，欲知佛說如來不能證諸佛法祕密義趣，當學如是甚深般若波羅蜜多。何以故？所證佛法及能證者不可得故。曼殊室利！若善男子、善女人等，欲知佛說如來不能證得無上正等菩提相好威儀無不具足祕密義趣，當學如是甚深般若波羅蜜多。何以故？所證無上正等菩提相好威儀及能證者不可得故。曼殊室利！若善男子、善女人等，欲知佛說如來不成一切功德不能化導一切有情祕密義趣，當學如是甚深般若波羅蜜多。何以故？一切功德所化有情及諸如來不可得故。曼殊室利！若善男子、善女人等欲於諸法得無礙解，當學如是甚深般若波羅蜜多。何以故？甚深般若波羅蜜多不見諸法有少真實若淨若染，生滅等故。曼殊室利！若善男子、善女人等，欲知諸法非去、來、今及無為相，當學如是甚深般若波羅蜜多。何以故？以真法界非去、來、今及無為故，諸法皆入真法界故。
「曼殊室利！若善男子、善女人等欲於諸法得無疑惑，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等，欲能三轉、十二行相無上法輪，及於其中都無執著，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等欲得慈心普覆一切，而於其中無有情想，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等，欲與世間同入法性無諸諍論，而於世間及諸諍論都無所得，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等，欲遍了達處、非處境都無罣礙，當學如是甚深般若波羅蜜多。曼殊室利！若善男子、善女人等，欲得如來力、無畏等無邊佛法，當學如是甚深般若波羅蜜多。」
爾時，曼殊室利童子即白佛言：「我觀如是甚深般若波羅蜜多，無相、無為，無諸功德，無生、無滅，無力、無能，無去、無來，無入、無出，無損、無益，無知、無見，無體、無用，非造作者，亦不能令諸法生滅，不令諸法為一、為異，無成、無壞，非慧、非境，非異生法、非聲聞法、非獨覺法、非菩薩法、非如來法，非證、不證，非得、不得，非盡、不盡，不入生死、不出生死，不入涅槃、不出涅槃，於諸佛法不成、不壞，於一切法非作、不作，非可思議、不可思議，離諸分別、絕諸戲論。如是般若波羅蜜多都無功德，云何如來勸有情類精勤修學？」
佛告曼殊室利童子：「如是所說即是般若波羅蜜多真實功德，善男子等若如是知，此即名為真實修學甚深般若波羅蜜多。
「復次，曼殊室利童子！若菩薩摩訶薩欲學菩薩勝三摩地，欲成菩薩勝三摩地，欲住如是三摩地中，見一切佛，知佛名字，及見如是諸佛世界，能證、能說諸法實相無障、無礙，當學如是甚深般若波羅蜜多，晝夜精勤勿生厭倦。」
曼殊室利即白佛言：「何故名為甚深般若波羅蜜多？」
佛告曼殊室利童子：「甚深般若波羅蜜多，無相、無名，無邊、無際，無歸依處，非思量境，非罪、非福，非闇、非明，如淨虛空等真法界，分齊、數量都不可得。由如是等種種因緣，是故名為甚深般若波羅蜜多。
「復次，曼殊室利童子！甚深般若波羅蜜多是諸菩薩甚深行處，若諸菩薩能行是處，於諸境界悉能通達，如是行處非一切乘之所行處。所以者何？如是行處無名、無相、非所分別，是故名為非所行處。」
曼殊室利復白佛言：「諸菩薩摩訶薩修行何法，疾證無上正等菩提？」
佛告曼殊室利童子：「若菩薩摩訶薩行深般若波羅蜜多心無懈倦，疾證無上正等菩提。
「復次，曼殊室利童子！若菩薩摩訶薩能正修行一相莊嚴三摩地者，疾證無上正等菩提。」
曼殊室利復白佛言：「云何名為一相莊嚴三摩地？諸菩薩眾云何修行？」
佛告曼殊室利童子：「此三摩地以法界相而為莊嚴，是故名為一相莊嚴三摩地。若菩薩摩訶薩欲入如是勝三摩地，先應聽聞、請問、修學甚深般若波羅蜜多，然後能入此三摩地。曼殊室利！若菩薩摩訶薩不動法界，知真法界不應動搖、不可思議、不可戲論，如是能入一相莊嚴三摩地。曼殊室利！若善男子、善女人等欲入如是三摩地者，應處空閑離諸諠雜，結跏趺坐不思眾相，為欲利樂一切有情，於一如來專心繫念，審取名字、善想容儀，隨所在方端身正向。相續繫念此一如來，即為普觀三世諸佛。所以者何？曼殊室利！一佛所有無量無邊功德、辯才等一切佛，三世諸佛乘一真如證大菩提無差別故。
「曼殊室利！若善男子、善女人等精勤修學，得入如是一相莊嚴三摩地者，普能了達無量無邊殑伽沙等諸佛法界無差別相，亦能總持無量無數殑伽沙等諸佛、菩薩已轉、未轉無上法輪。如阿難陀多聞智慧，於諸佛教得念總持，聲聞眾中雖最為勝，而所持教猶有分限。若得如是一相莊嚴三摩地者，多聞智慧、念總持力不可思議，普能受持無量無數殑伽沙等諸佛、菩薩無上法輪，一一法門皆能了達甚深義趣，宣說、開示，辯才無盡，勝阿難陀多百千倍。」
曼殊室利即白佛言：「彼菩薩乘善男子等，云何得此三摩地時便獲無邊功德勝利？」
佛言：「童子！彼菩薩乘善男子等，精勤修學一相莊嚴三摩地者，常作是念：『我當云何能普通達諸佛法界，受持一切無上法輪，與諸有情作大饒益？』由斯得此三摩地時，便獲無邊功德勝利。曼殊室利！彼菩薩乘善男子等，先聞如是一相莊嚴三摩地功德，發勤精進繫念思惟，如如思惟此定功德，如是如是功德相現；既見此相如先所聞，深生歡喜轉勤修習，漸次得入此三摩地，功德勝利不可思議。若諸有情毀謗正法，不信善惡、業障重者，彼於此定不能證得。
「曼殊室利！譬如有人遇得寶珠，示治寶者言：『我此寶價直無量，然其形色未甚光鮮，汝當為我如法磨瑩，但令鮮淨勿壞形色。』其治寶者隨彼所言，依法專心如如磨瑩，如是如是光色漸發，乃至究竟映徹表裏，既修治已價直無量。曼殊室利！彼菩薩乘善男子等，漸次修學此三摩地亦復如是，乃至得此三摩地時，便獲無邊功德勝利。曼殊室利！譬如日輪普放光明作大饒益，如是若得一相莊嚴三摩地時，普照法界，亦能了達一切法門，為諸有情作大饒益，功德勝利不可思議。
「曼殊室利！如我所說種種法門皆同一味，謂遠離味、解脫味、寂滅味，無所乖違。彼菩薩乘善男子等，若得如是三摩地時，所演法門亦同一味，謂遠離味、解脫味、寂滅味，無所乖違。彼菩薩乘善男子等，若得如是三摩地時，隨演法門辯說無盡，速能成滿菩提分法。是故，曼殊室利童子！若菩薩摩訶薩能正修行一相莊嚴三摩地者，疾證無上正等菩提。
「復次，曼殊室利童子！若菩薩摩訶薩不見法界種種差別及一相者，疾證無上正等菩提。若菩薩乘善男子等忍菩薩法不應修行，忍大菩提不應求趣，達一切法本性空故，彼由此忍疾證無上正等菩提。若菩薩乘善男子等信一切法皆是佛法，聞一切空心不驚疑，由此因故疾證無上正等菩提。若菩薩乘善男子等聞說諸法無不皆空，心不迷悶亦無疑惑，彼於佛法常不捨離，疾證無上正等菩提。」
爾時，曼殊室利童子聞是語已即白佛言：「諸佛無上正等菩提，定由因緣而證得不？」
佛言：「不爾！」
曼殊室利復白佛言：「諸佛無上正等菩提，不由因緣而證得不？」
佛言：「不爾！所以者何？不思議界不由因緣及非因緣而可證得，諸佛無上正等菩提當知即是不思議界。
「曼殊室利！若善男子、善女人等聞如是說心不驚怖；我說彼於無量佛所，已發大願、多種善根，是故苾芻、苾芻尼等，聞說如是甚深般若波羅蜜多，心不驚疑亦不迷悶，彼為真實隨佛出家。若近事男、近事女等，聞說如是甚深般若波羅蜜多，心不驚疑亦不迷悶，彼為真實歸佛、法、僧。若菩薩乘善男子等，不學如是甚深般若波羅蜜多，彼不名為真實修學菩薩乘者。曼殊室利！譬如世間卉木、叢林、藥物、種子，一切皆依大地生長；如是菩薩世、出世間一切善根及餘勝事，無不皆依甚深般若波羅蜜多而得生長。當知如是甚深般若波羅蜜多所攝受法，皆於無上正等菩提隨順證得無所乖諍。」
爾時，曼殊室利童子聞佛所說，便白佛言：「此贍部洲當來之世，於何城邑聚落處所演說、開示甚深般若波羅蜜多人多信受？」
佛告曼殊室利童子：「今此眾中善男子等聞說般若波羅蜜多，信受修行，歡喜發願：『願我當來隨所生處，常聞般若波羅蜜多。』隨彼當來所生之處，宿願力故，即有如是甚深般若波羅蜜多演說、開示人多信受。曼殊室利！善男子等聞說般若波羅蜜多，歡喜踊躍深信受者，我說彼類久殖善根，乘宿願力乃能如是。曼殊室利！有欲聽受甚深般若波羅蜜多，汝應告言：『善男子等！隨意聽受勿生驚怖，疑惑、不信反增謗毀。』今此般若波羅蜜多甚深經中不顯有法，謂不顯有若異生法、若聲聞法、若獨覺法、若菩薩法、若如來法成壞可得。」
曼殊室利即白佛言：「若有苾芻、苾芻尼等來至我所，作是問言：『云何如來為眾宣說甚深般若波羅蜜多？』我當答言：『佛說諸法無違諍相。所以者何？都無有法能與法諍，亦無有情於佛所說能生信解。所以者何？諸有情類都不可得。』
「復次，世尊！我當告彼：『如來常說諸法實際。所以者何？諸法平等，無不皆是實際所攝，此中不說阿羅漢等能逮勝法。所以者何？阿羅漢等所證得法與異生法無差別相。』
「復次，世尊！我當告彼：『佛所說法，不令有情於般涅槃已、正、當得。何以故？以諸有情畢竟空故。』
「復次，世尊！善男子等來至我所，作是問言：『仁與如來嘗所談論甚深般若波羅蜜多，請為說之，今希聽受！』我當告彼：『汝等欲聞，勿起聽心，勿專繫念，當起如幻如化等心，如是乃能解我所說。汝等若欲聽我法者，當起是心：「今所聞法如空鳥跡、如石女兒。」如是乃能聽我所說。汝等若欲聞我法者，勿起二想。所以者何？我所說法遠離二想。汝等今應不壞我想、不起諸見，於諸佛法無所希求，異生法中不樂遷動。何以故？二法相空，無取捨故。』
「世尊！諸有請我宣說甚深般若波羅蜜多，我先如是教誡教授，以無相印印定諸法，令求聽者離取著心，然後為說甚深般若波羅蜜多相應之法。」
佛讚曼殊室利童子：「善哉，善哉！汝能善說我所說法及說方便。
「曼殊室利！若善男子、善女人等欲見如來，欲親近佛供養恭敬，應學如是甚深般若波羅蜜多。若諸有情欲請諸佛為大師者，應學如是甚深般若波羅蜜多。若諸有情欲證無上正等菩提，或不欲證，應學如是甚深般若波羅蜜多。若諸有情於一切定欲得善巧，應學如是甚深般若波羅蜜多。若諸有情於一切定欲自在起，應學如是甚深般若波羅蜜多。所以者何？諸三摩地要知諸法無生無滅、無作無為方自在起。何以故？達諸法空無罣礙故。若諸有情欲達諸法皆有出離，無有一法無出離者，應學如是甚深般若波羅蜜多。若諸有情欲達諸法但假施設無真實者，應學如是甚深般若波羅蜜多。若欲了知諸有情類雖趣無上正等菩提，而無有情趣菩提者亦無退沒，應學如是甚深般若波羅蜜多。何以故？達一切法即菩提故。若欲了達一切有情行菩提行，無不行者亦無退沒，應學如是甚深般若波羅蜜多。所以者何？菩提即是諸法實性，一切有情皆行諸法，無捨法者，諸行皆空，故無退沒。若欲了達一切法性即是菩提，一切菩提即是法界，此即實際，實際即空，心無退沒，應學如是甚深般若波羅蜜多。
「曼殊室利！甚深般若波羅蜜多，顯示諸佛難思作用饒益有情，亦是如來所遊戲處。所以者何？甚深般若波羅蜜多不可示現，不可宣說，是無墮法；唯有如來如實覺了，方便善巧為有情說。
「曼殊室利！若有苾芻、苾芻尼等於深般若波羅蜜多，下至受持一四句頌為他演說，定趣菩提住佛境界，況能如說而修行者！當知是人不墮惡趣，疾證無上正等菩提。
「曼殊室利！若諸有情聞說如是甚深般若波羅蜜多，心不沈沒，亦不驚怖，歡喜信受，當知此輩於諸佛法定當證得，一切如來皆所印可，開許領受為弟子眾。
「曼殊室利！若善男子、善女人等，信受如來無上法印，謂深般若波羅蜜多，獲無量福。如是法印，一切如來、應、正等覺共所護念，諸阿羅漢、菩薩、智者及諸天神皆共守衛。若菩薩乘善男子等此印所印，超諸惡趣、聲聞、獨覺，定當證得無上菩提。」
時，天帝釋即與無量三十三天諸天子等，各取種種天妙華香、嗢鉢羅花、拘某陀花、鉢特摩花、奔茶利花、微妙音花、妙靈瑞花、栴檀香末，供養般若波羅蜜多，奉散如來、曼殊室利、一切菩薩及聲聞等；復奏種種天諸音樂，歌讚妙法而為供養；復發願言：「願我等輩常聞如是甚深般若波羅蜜多無上法印！」
時，天帝釋復發願言：「願贍部洲諸有情類，常聞般若波羅蜜多，歡喜受持、成辦佛法！我等天眾常衛護之，令受持者無諸留難。諸有情類少用功力而得聽聞、受持、讀誦，當知皆是諸天威力。」
爾時，佛讚天帝釋言：「天主！汝今能發是願，若有聞此歡喜受持，於諸佛法定能成辦，疾趣無上正等菩提。」
曼殊室利即白佛言：「唯願如來以神通力，護持般若波羅蜜多久住世間饒益一切。」
佛時即現大神通力，令此三千大千世界諸山、大地六反振動；復現微笑，放大光明普照三千大千世界。
曼殊室利便白佛言：「此即如來現神通力護持般若波羅蜜多久住世間饒益之相。」
佛言：「如是！如汝所說。我以神力護持般若波羅蜜多無上法印，令久住世饒益有情。諸佛世尊說勝法已，法爾皆起大神通力，護持此法令住世間，使諸天魔不能得便，諸惡人輩不能謗毀，一切外道深心怖畏。若有精勤學此法者，一切障難無不殄滅。」
時，薄伽梵說是經已，一切菩薩摩訶薩眾，曼殊室利而為上首，及苾芻等四部大眾，天、龍、藥叉、阿素洛等一切眾會，聞佛所說皆大歡喜、信受奉行。', '已發布'),
  (3, '大般若波羅蜜多經卷第五百七十八', '三藏法師玄奘奉　詔譯', '第十般若理趣分
如是我聞：一時，薄伽梵妙善成就一切如來金剛住持平等性智種種希有殊勝功德，已能善獲一切如來灌頂寶冠超過三界，已能善得一切如來遍金剛智大觀自在，已得圓滿一切如來決定諸法大妙智印，已善圓證一切如來畢竟空寂平等性印；於諸能作、所作事業，皆得善巧成辦無餘；一切有情種種希願，隨其無罪皆能滿足，已善安住三世平等，常無斷盡；廣大遍照身語心性，猶若金剛等諸如來，無動無壞。
是薄伽梵住欲界頂他化自在天王宮中一切如來常所遊處、咸共稱美大寶藏殿。其殿無價末尼所成，種種珍奇間雜嚴飾，眾色交暎放大光明；寶鐸、金鈴處處懸列，微風吹動出和雅音；綺蓋、繒幡、花幢、綵拂、寶珠、瓔珞、半滿月等，種種雜飾而用莊嚴，賢聖、天仙之所愛樂。與八十億大菩薩俱，一切皆具陀羅尼門、三摩地門無礙妙辯，如是等類無量功德，設經多劫讚不能盡，其名曰金剛手菩薩摩訶薩、觀自在菩薩摩訶薩、虛空藏菩薩摩訶薩、金剛拳菩薩摩訶薩、妙吉祥菩薩摩訶薩、大空藏菩薩摩訶薩、發心即轉法輪菩薩摩訶薩、摧伏一切魔怨菩薩摩訶薩。如是上首有八百萬大菩薩眾前後圍繞，宣說正法，初、中、後善，文義巧妙，純一圓滿，清白梵行。
爾時，世尊為諸菩薩說一切法甚深微妙般若理趣清淨法門，此門即是菩薩句義。云何名為菩薩句義？謂：
「極妙樂清淨句義是菩薩句義；諸見永寂清淨句義是菩薩句義；微妙適悅清淨句義是菩薩句義；渴愛永息清淨句義是菩薩句義；胎藏超越清淨句義是菩薩句義；眾德莊嚴清淨句義是菩薩句義；意極猗適清淨句義是菩薩句義；得大光明清淨句義是菩薩句義；身善安樂清淨句義是菩薩句義，語善安樂清淨句義是菩薩句義，意善安樂清淨句義是菩薩句義；色蘊空寂清淨句義是菩薩句義，受、想、行、識蘊空寂清淨句義是菩薩句義；眼處空寂清淨句義是菩薩句義，耳、鼻、舌、身、意處空寂清淨句義是菩薩句義；色處空寂清淨句義是菩薩句義，聲、香、味、觸、法處空寂清淨句義是菩薩句義；眼界空寂清淨句義是菩薩句義，耳、鼻、舌、身、意界空寂清淨句義是菩薩句義；色界空寂清淨句義是菩薩句義，聲、香、味、觸、法界空寂清淨句義是菩薩句義；眼識界空寂清淨句義是菩薩句義，耳、鼻、舌、身、意識界空寂清淨句義是菩薩句義；眼觸空寂清淨句義是菩薩句義，耳、鼻、舌、身、意觸空寂清淨句義是菩薩句義；眼觸為緣所生諸受空寂清淨句義是菩薩句義，耳、鼻、舌、身、意觸為緣所生諸受空寂清淨句義是菩薩句義；地界空寂清淨句義是菩薩句義，水、火、風、空、識界空寂清淨句義是菩薩句義；苦聖諦空寂清淨句義是菩薩句義，集、滅、道聖諦空寂清淨句義是菩薩句義；因緣空寂清淨句義是菩薩句義，等無間緣、所緣緣、增上緣空寂清淨句義是菩薩句義；無明空寂清淨句義是菩薩句義，行、識、名色、六處、觸、受、愛、取、有、生、老死空寂清淨句義是菩薩句義；布施波羅蜜多空寂清淨句義是菩薩句義，淨戒、安忍、精進、靜慮、般若波羅蜜多空寂清淨句義是菩薩句義；真如空寂清淨句義是菩薩句義，法界、法性、不虛妄性、不變異性、平等性、離生性、法定、法住、實際、虛空界、不思議界空寂清淨句義是菩薩句義；四靜慮空寂清淨句義是菩薩句義；四無量、四無色定空寂清淨句義是菩薩句義；四念住空寂清淨句義是菩薩句義，四正斷、四神足、五根、五力、七等覺支、八聖道支空寂清淨句義是菩薩句義；空解脫門空寂清淨句義是菩薩句義，無相、無願解脫門空寂清淨句義是菩薩句義；八解脫空寂清淨句義是菩薩句義，八勝處、九次第定、十遍處空寂清淨句義是菩薩句義；極喜地空寂清淨句義是菩薩句義，離垢地、發光地、焰慧地、極難勝地、現前地、遠行地、不動地、善慧地、法雲地空寂清淨句義是菩薩句義；淨觀地空寂清淨句義是菩薩句義，種性地、第八地、具見地、薄地、離欲地、已辦地、獨覺地、菩薩地、如來地空寂清淨句義是菩薩句義；一切陀羅尼門空寂清淨句義是菩薩句義，一切三摩地門空寂清淨句義是菩薩句義；五眼空寂清淨句義是菩薩句義，六神通空寂清淨句義是菩薩句義；如來十力空寂清淨句義是菩薩句義，四無所畏、四無礙解、大慈、大悲、大喜、大捨、十八佛不共法空寂清淨句義是菩薩句義；三十二相空寂清淨句義是菩薩句義，八十隨好空寂清淨句義是菩薩句義；無忘失法空寂清淨句義是菩薩句義，恒住捨性空寂清淨句義是菩薩句義；一切智空寂清淨句義是菩薩句義，道相智、一切相智空寂清淨句義是菩薩句義；一切菩薩摩訶薩行空寂清淨句義是菩薩句義，諸佛無上正等菩提空寂清淨句義是菩薩句義；一切異生法空寂清淨句義是菩薩句義，一切預流、一來、不還、阿羅漢、獨覺、菩薩、如來法空寂清淨句義是菩薩句義；一切善非善法空寂清淨句義是菩薩句義，一切有記無記法、有漏無漏法、有為無為法、世間出世間法空寂清淨句義是菩薩句義。
「所以者何？以一切法自性空故自性遠離，由遠離故自性寂靜，由寂靜故自性清淨，由清淨故甚深般若波羅蜜多最勝清淨。如是般若波羅蜜多，當知即是菩薩句義，諸菩薩眾皆應修學。」
佛說如是菩薩句義般若理趣清淨法已，告金剛手菩薩等言：「若有得聞此一切法甚深微妙般若理趣清淨法門深信受者，乃至當坐妙菩提座，一切障蓋皆不能染，謂煩惱障、業障、報障，雖多積集而不能染；雖造種種極重惡業而易消滅，不墮惡趣。若能受持日日讀誦，精勤無間，如理思惟，彼於此生，定得一切法平等性金剛等持，於一切法皆得自在，恒受一切勝妙喜樂，當經十六大菩薩生，定得如來執金剛性，疾證無上正等菩提。」
爾時，世尊復依遍照如來之相，為諸菩薩宣說般若波羅蜜多一切如來寂靜法性甚深理趣現等覺門，謂：「金剛平等性現等覺門，以大菩提堅實難壞如金剛故；義平等性現等覺門，以大菩提其義一故；法平等性現等覺門，以大菩提自性淨故；一切法平等性現等覺門，以大菩提於一切法無分別故。」
佛說如是寂靜法性般若理趣現等覺已，告金剛手菩薩等言：「若有得聞如是四種般若理趣現等覺門信解、受持、讀誦、修習，乃至當坐妙菩提座，雖造一切極重惡業，而能超越一切惡趣，疾證無上正等菩提。」
爾時，世尊復依調伏一切惡法釋迦牟尼如來之相，為諸菩薩宣說般若波羅蜜多攝受一切法平等性甚深理趣普勝法門，謂：「貪欲性無戲論故，瞋恚性亦無戲論；瞋恚性無戲論故，愚癡性亦無戲論；愚癡性無戲論故，猶豫性亦無戲論；猶豫性無戲論故，諸見性亦無戲論；諸見性無戲論故，憍慢性亦無戲論；憍慢性無戲論故，諸纏性亦無戲論；諸纏性無戲論故，煩惱垢性亦無戲論；煩惱垢性無戲論故，諸惡業性亦無戲論；諸惡業性無戲論故，諸果報性亦無戲論；諸果報性無戲論故，雜染法性亦無戲論；雜染法性無戲論故，清淨法性亦無戲論；清淨法性無戲論故，一切法性亦無戲論；一切法性無戲論故，當知般若波羅蜜多亦無戲論。」
佛說如是調伏眾惡般若理趣普勝法已，告金剛手菩薩等言：「若有得聞如是般若波羅蜜多甚深理趣信解、受持、讀誦、修習，假使殺害三界所攝一切有情，而不由斯墮於地獄、傍生、鬼界，以能調伏一切煩惱及隨煩惱惡業等故；常生善趣受勝妙樂，修諸菩薩摩訶薩行，疾證無上正等菩提。」
爾時，世尊復依性淨如來之相，為諸菩薩宣說般若波羅蜜多一切法平等性觀自在妙智印甚深理趣清淨法門，謂：「一切貪欲本性清淨極照明故，能令世間瞋恚清淨；一切瞋恚本性清淨極照明故，能令世間愚癡清淨；一切愚癡本性清淨極照明故，能令世間疑惑清淨；一切疑惑本性清淨極照明故，能令世間見趣清淨；一切見趣本性清淨極照明故，能令世間憍慢清淨；一切憍慢本性清淨極照明故，能令世間纏結清淨；一切纏結本性清淨極照明故，能令世間垢穢清淨；一切垢穢本性清淨極照明故，能令世間惡法清淨；一切惡法本性清淨極照明故，能令世間生死清淨；一切生死本性清淨極照明故，能令世間諸法清淨；以一切法本性清淨極照明故，能令世間有情清淨；一切有情本性清淨極照明故，能令世間一切智清淨；以一切智本性清淨極照明故，能令世間甚深般若波羅蜜多最勝清淨。」
佛說如是平等智印般若理趣清淨法已，告金剛手菩薩等言：「若有得聞如是般若波羅蜜多清淨理趣信解、受持、讀誦、修習，雖住一切貪、瞋、癡等客塵、煩惱、垢穢聚中，而猶蓮華不為一切客塵、垢穢、過失所染，常能修習菩薩勝行，疾證無上正等菩提。」
爾時，世尊復依一切三界勝主如來之相，為諸菩薩宣說般若波羅蜜多一切如來和合灌頂甚深理趣智藏法門，謂：「以世間灌頂位施，當得三界法王位果；以出世間無上義施，當得一切希願滿足；以出世間無上法施，於一切法當得自在；若以世間財食等施，當得一切身、語、心樂；若以種種財法等施，能令布施波羅蜜多速得圓滿；受持種種清淨禁戒，能令淨戒波羅蜜多速得圓滿；於一切事修學安忍，能令安忍波羅蜜多速得圓滿；於一切時修習精進，能令精進波羅蜜多速得圓滿；於一切境修行靜慮，能令靜慮波羅蜜多速得圓滿；於一切法常修妙慧，能令般若波羅蜜多速得圓滿。」
佛說如是灌頂法門般若理趣智藏法已，告金剛手菩薩等言：「若有得聞如是灌頂甚深理趣智藏法門信解、受持、讀誦、修習，速能滿足諸菩薩行，疾證無上正等菩提。」
爾時，世尊復依一切如來智印持一切佛祕密法門如來之相，為諸菩薩宣說般若波羅蜜多一切如來住持智印甚深理趣金剛法門，謂：「具攝受一切如來金剛身印，當證一切如來法身；若具攝受一切如來金剛語印，於一切法當得自在；若具攝受一切如來金剛心印，於一切定當得自在；若具攝受一切如來金剛智印，能得最上妙身、語、心，猶若金剛無動無壞。」
佛說如是如來智印般若理趣金剛法已，告金剛手菩薩等言：「若有得聞如是智印甚深理趣金剛法門信解、受持、讀誦、修習，一切事業皆能成辦，常與一切勝事和合，所欲修行一切勝智，諸勝福業皆速圓滿，當獲最勝淨身、語、心，猶若金剛不可破壞，疾證無上正等菩提。」
爾時，世尊復依一切無戲論法如來之相，為諸菩薩宣說般若波羅蜜多甚深理趣輪字法門，謂：「一切法空，無自性故；一切法無相，離眾相故；一切法無願，無所願故；一切法遠離，無所著故；一切法寂靜，永寂滅故；一切法無常，性常無故；一切法無樂，非可樂故；一切法無我，不自在故；一切法無淨，離淨相故；一切法不可得，推尋其性不可得故；一切法不思議，思議其性無所有故；一切法無所有，眾緣和合假施設故；一切法無戲論，本性空寂離言說故；一切法本性淨，甚深般若波羅蜜多本性淨故。」
佛說如是離諸戲論般若理趣輪字法已，告金剛手菩薩等言：「若有得聞此無戲論般若理趣輪字法門信解、受持、讀誦、修習，於一切法得無礙智，疾證無上正等菩提。」
爾時，世尊復依一切如來輪攝如來之相，為諸菩薩宣說般若波羅蜜多入廣大輪甚深理趣平等性門，謂：「入金剛平等性，能入一切如來性輪故；入義平等性，能入一切菩薩性輪故；入法平等性，能入一切法性輪故；入蘊平等性，能入一切蘊性輪故；入處平等性，能入一切處性輪故；入界平等性，能入一切界性輪故；入諦平等性，能入一切諦性輪故；入緣起平等性，能入一切緣起性輪故；入寶平等性，能入一切寶性輪故；入食平等性，能入一切食性輪故；入善法平等性，能入一切善法性輪故；入非善法平等性，能入一切非善法性輪故；入有記法平等性，能入一切有記法性輪故；入無記法平等性，能入一切無記法性輪故；入有漏法平等性，能入一切有漏法性輪故；入無漏法平等性，能入一切無漏法性輪故；入有為法平等性，能入一切有為法性輪故；入無為法平等性，能入一切無為法性輪故；入世間法平等性，能入一切世間法性輪故；入出世間法平等性，能入一切出世間法性輪故；入異生法平等性，能入一切異生法性輪故，入聲聞法平等性，能入一切聲聞法性輪故；入獨覺法平等性，能入一切獨覺法性輪故；入菩薩法平等性，能入一切菩薩法性輪故；入如來法平等性，能入一切如來法性輪故；入有情平等性，能入一切有情性輪故；入一切平等性，能入一切性輪故。」
佛說如是入廣大輪般若理趣平等性已，告金剛手菩薩等言：「若有得聞如是輪性甚深理趣平等性門信解、受持、讀誦、修習，能善悟入諸平等性，疾證無上正等菩提。」
爾時，世尊復依一切廣受供養真淨器田如來之相，為諸菩薩宣說般若波羅蜜多一切供養甚深理趣無上法門，謂：「發無上正等覺心，於諸如來廣設供養；攝護正法，於諸如來廣設供養；修行一切波羅蜜多，於諸如來廣設供養；修行一切菩提分法，於諸如來廣設供養；修行一切總持、等持，於諸如來廣設供養；修行一切五眼、六通，於諸如來廣設供養；修行一切靜慮、解脫，於諸如來廣設供養；修行一切慈、悲、喜、捨，於諸如來廣設供養；修行一切佛不共法，於諸如來廣設供養；觀一切法若常、若無常皆不可得，於諸如來廣設供養；觀一切法若樂、若苦皆不可得，於諸如來廣設供養；觀一切法若我、若無我皆不可得，於諸如來廣設供養；觀一切法若淨、若不淨皆不可得，於諸如來廣設供養；觀一切法若空、若不空皆不可得，於諸如來廣設供養；觀一切法若有相、若無相皆不可得，於諸如來廣設供養；觀一切法若有願、若無願皆不可得，於諸如來廣設供養；觀一切法若遠離、若不遠離皆不可得，於諸如來廣設供養；觀一切法若寂靜、若不寂靜皆不可得，於諸如來廣設供養；於深般若波羅蜜多，書寫、聽聞、受持、讀誦、思惟、修習，廣為有情宣說流布，或自供養或轉施他，於諸如來廣設供養。」
佛說如是真淨供養甚深理趣無上法已，告金剛手菩薩等言：「若有得聞如是供養般若理趣無上法門信解、受持、讀誦、修習，速能圓滿諸菩薩行，疾證無上正等菩提。」
爾時，世尊復依一切能善調伏如來之相，為諸菩薩宣說般若波羅蜜多攝受智密調伏有情甚深理趣智藏法門謂：「一切有情平等性即忿平等性，一切有情調伏性即忿調伏性，一切有情真法性即忿真法性，一切有情真如性即忿真如性，一切有情法界性即忿法界性，一切有情離生性即忿離生性，一切有情實際性即忿實際性，一切有情本空性即忿本空性，一切有情無相性即忿無相性，一切有情無願性即忿無願性，一切有情遠離性即忿遠離性，一切有情寂靜性即忿寂靜性，一切有情不可得性即忿不可得性，一切有情無所有性即忿無所有性，一切有情難思議性即忿難思議性，一切有情無戲論性即忿無戲論性，一切有情如金剛性即忿如金剛性。所以者何？一切有情真調伏性即是無上正等菩提，亦是般若波羅蜜多，亦是諸佛一切智智。」
佛說如是能善調伏甚深理趣智藏法已，告金剛手菩薩等言：「若有得聞如是調伏般若理趣智藏法門信解、受持、讀誦、修習，能自調伏忿恚等過，亦能調伏一切有情，常生善趣受諸妙樂，現世怨敵皆起慈心，能善修行諸菩薩行，疾證無上正等菩提。」
爾時，世尊復依一切能善建立性平等法如來之相，為諸菩薩宣說般若波羅蜜多一切法性甚深理趣最勝法門，謂：「一切有情性平等故，甚深般若波羅蜜多亦性平等；一切法性平等故，甚深般若波羅蜜多亦性平等；一切有情性調伏故，甚深般若波羅蜜多亦性調伏；一切法性調伏故，甚深般若波羅蜜多亦性調伏；一切有情有實義故，甚深般若波羅蜜多亦有實義；一切法有實義故，甚深般若波羅蜜多亦有實義；一切有情即真如故，甚深般若波羅蜜多亦即真如；一切法即真如故，甚深般若波羅蜜多亦即真如；一切有情即法界故，甚深般若波羅蜜多亦即法界；一切法即法界故，甚深般若波羅蜜多亦即法界；一切有情即法性故，甚深般若波羅蜜多亦即法性；一切法即法性故，甚深般若波羅蜜多亦即法性；一切有情即實際故，甚深般若波羅蜜多亦即實際；一切法即實際故，甚深般若波羅蜜多亦即實際；一切有情即本空故，甚深般若波羅蜜多亦即本空；一切法即本空故，甚深般若波羅蜜多亦即本空；一切有情即無相故，甚深般若波羅蜜多亦即無相；一切法即無相故，甚深般若波羅蜜多亦即無相；一切有情即無願故，甚深般若波羅蜜多亦即無願；一切法即無願故，甚深般若波羅蜜多亦即無願；一切有情即遠離故，甚深般若波羅蜜多亦即遠離；一切法即遠離故，甚深般若波羅蜜多亦即遠離；一切有情即寂靜故，甚深般若波羅蜜多亦即寂靜；一切法即寂靜故，甚深般若波羅蜜多亦即寂靜；一切有情不可得故，甚深般若波羅蜜多亦不可得；一切法不可得故，甚深般若波羅蜜多亦不可得；一切有情無所有故，甚深般若波羅蜜多亦無所有；一切法無所有故，甚深般若波羅蜜多亦無所有；一切有情不思議故，甚深般若波羅蜜多亦不思議；一切法不思議故，甚深般若波羅蜜多亦不思議；一切有情無戲論故，甚深般若波羅蜜多亦無戲論；一切法無戲論故，甚深般若波羅蜜多亦無戲論；一切有情無邊際故，甚深般若波羅蜜多亦無邊際；一切法無邊際故，甚深般若波羅蜜多亦無邊際；一切有情有業用故，當知般若波羅蜜多亦有業用；一切法有業用故，當知般若波羅蜜多亦有業用。」
佛說如是性平等性甚深理趣最勝法已，告金剛手菩薩等言：「若有得聞如是平等般若理趣最勝法門信解、受持、讀誦、修習，則能通達平等法性甚深般若波羅蜜多，於諸有情心無罣礙，疾證無上正等菩提。」
爾時，世尊復依一切住持藏法如來之相，為諸菩薩宣說般若波羅蜜多一切有情住持遍滿甚深理趣勝藏法門，謂：「一切有情皆如來藏，普賢菩薩自體遍故；一切有情皆金剛藏，以金剛藏所灌灑故；一切有情皆正法藏，一切皆隨正語轉故；一切有情皆妙業藏，一切事業加行依故。」
佛說如是有情住持甚深理趣勝藏法已，告金剛手菩薩等言：「若有得聞如是遍滿般若理趣勝藏法門信解、受持、讀誦、修習，則能通達勝藏法性，疾證無上正等菩提。」
爾時，世尊復依究竟無邊際法如來之相，為諸菩薩宣說般若波羅蜜多究竟住持法義平等金剛法門，謂：「甚深般若波羅蜜多無邊故，一切如來亦無邊；甚深般若波羅蜜多無際故，一切如來亦無際；甚深般若波羅蜜多一味故，一切法亦一味；甚深般若波羅蜜多究竟故，一切法亦究竟。」
佛說如是無邊無際究竟理趣金剛法已，告金剛手菩薩等言：「若有得聞如是究竟般若理趣金剛法門信解、受持、讀誦、修習，一切障法皆悉消除，定得如來執金剛性，疾證無上正等菩提。」
爾時，世尊復依遍照如來之相，為諸菩薩宣說般若波羅蜜多得諸如來祕密法性及一切法無戲論性、大樂金剛不空神呪金剛法門，初、中、後位最勝第一甚深理趣無上法門，謂：「大貪等最勝成就，令大菩薩大樂最勝成就；大樂最勝成就，令大菩薩一切如來大覺最勝成就；一切如來大覺最勝成就，令大菩薩降伏一切大魔最勝成就；降伏一切大魔最勝成就，令大菩薩普大三界自在最勝成就；普大三界自在最勝成就，令大菩薩能無遺餘拔有情界，利益安樂一切有情，畢竟大樂最勝成就所以者何？乃至生死流轉住處，有勝智者齊此常能以無等法，饒益有情不入寂滅；又以般若波羅蜜多方便善巧成立勝智，善辦一切清淨事業，能令諸有皆得清淨；又以貪等調伏世間，普遍恒時乃至諸有，皆令清淨自然調伏；又如蓮華形色光淨，不為一切穢物所染。如是貪等饒益世間，住過有過常不能染。又大貪等能得清淨、大樂、大財、三界自在，常能堅固饒益有情。」
爾時，如來即說神呪：
「納慕薄伽筏帝(一)　鉢剌壤波囉弭多曳(二)　薄底(丁履反)筏攃(七葛反)羅曳(三)　罨跛履弭多窶拏曳(四)　薩縛呾他揭多跛履布視多曳(五)　薩縛呾他揭多奴壤多奴壤多邲壤多曳(六)　呾姪他(七)　鉢剌(口+陀)(一弟反)鉢剌(口+陀)(八)　莫訶鉢喇(口+陀)(九)　鉢剌壤婆娑羯囇(十)　鉢剌壤路迦羯囇(十一)　案馱迦囉毘談末埿(十二)　悉遞(十三)　蘇悉遞(十四)　悉殿都漫薄伽筏底(十五)　薩防伽孫達囇(十六)　薄底筏攃囇(十七)　鉢剌娑履多喝悉帝(十八)　參磨濕嚩娑羯囇(十九)勃勃[(二十)　悉   悉  (二十一)　劍波劍波(二十二)　浙羅浙羅(二十三)　曷邏嚩曷邏嚩(二十四)　阿揭車阿揭車(二十五)　薄伽筏底(二十六)　麼毘濫婆(二十七)　莎訶(二十八) 
「如是神呪，三世諸佛皆共宣說、同所護念，能受持者一切障滅，隨心所欲無不成辦，疾證無上正等菩提。」
爾時，如來復說神呪：
「納慕薄伽筏帝(一)　鉢剌壤波囉弭多曳(二)　呾姪他(三)　牟尼達䜝(四)　僧揭洛訶達䜝(五)　遏奴揭洛訶達䜝(六)　毘目底達䜝(七)　薩馱奴揭洛訶達䜝(八)　吠室洛末拏達䜝(九)　參漫多奴跛履筏剌呾那達䜝(十)　窶拏僧揭洛訶達䜝(十一)　薩縛迦羅跛履波剌那達䜝(十二)　莎訶 (十三)
「如是神呪是諸佛母，能誦持者一切罪滅，常見諸佛得宿住智，疾證無上正等菩提。」
爾時，如來復說神呪：
「納慕薄伽筏帝(一)　鉢剌壤波囉弭多曳(二)　呾姪他(三)　室囇曳(四)　室囇曳(五)　室囇曳(六)　室囇曳細(七)　莎訶(八)
「如是神呪具大威力，能受持者業障消除，所聞正法總持不忘，疾證無上正等菩提。」
爾時，世尊說是呪已，告金剛手菩薩等言：「若諸有情於每日旦，至心聽誦如是般若波羅蜜多甚深理趣最勝法門無間斷者，諸惡業障皆得消滅，諸勝喜樂常現在前，大樂金剛不空神呪現身必得，究竟成滿一切如來金剛祕密最勝成就，不久當得大執金剛及如來性。若有情類未多佛所植眾善根、久發大願，於此般若波羅蜜多甚深理趣最勝法門，不能聽聞、書寫、讀誦、供養恭敬、思惟、修習；要多佛所植眾善根、久發大願，乃能於此甚深理趣最勝法門，下至聽聞一句一字，況能具足讀誦、受持！若諸有情供養恭敬、尊重讚歎八十殑伽沙等俱胝那庾多佛，乃能具足聞此般若波羅蜜多甚深理趣。若地方所流行此經，一切天、人、阿素洛等皆應供養如佛制多。有置此經在身或手，諸天、人等皆應禮敬。若有情類受持此經多俱胝劫，得宿住智，常勤精進修諸善法，惡魔外道不能稽留；四大天王及餘天眾，常隨擁衛未曾暫捨，終不橫死抂遭衰患；諸佛菩薩常共護持，令一切時善增惡減；於諸佛土隨願往生，乃至菩提不墮惡趣。諸有情類受持此經，定獲無邊勝利功德，我今略說如是少分。」
時，薄伽梵說是經已，金剛手等諸大菩薩及餘天眾，聞佛所說皆大歡喜、信受奉行。', '已發布'),
  (4, '妙法蓮華經', null, '爾時世尊告舍利弗：「汝已慇懃三請，豈得不說。汝今諦聽，善思念之，吾當為汝分別解說。」說此語時，會中有比丘、比丘尼、優婆塞、優婆夷五千人等，即從座起，禮佛而退。所以者何？此輩罪根深重及增上慢，未得謂得、未證謂證，有如此失，是以不住。世尊默然而不制止。
爾時佛告舍利弗：「我今此眾，無復枝葉，純有貞實。舍利弗！如是增上慢人，退亦佳矣。汝今善聽，當為汝說。」
舍利弗言：「唯然，世尊！願樂欲聞。」
佛告舍利弗：「如是妙法，諸佛如來時乃說之，如優曇鉢華，時一現耳。舍利弗！汝等當信佛之所說，言不虛妄。舍利弗！諸佛隨宜說法，意趣難解。所以者何？我以無數方便，種種因緣、譬喻言辭，演說諸法。是法非思量分別之所能解，唯有諸佛乃能知之。所以者何？諸佛世尊唯以一大事因緣故出現於世。舍利弗！云何名諸佛世尊唯以一大事因緣故出現於世？諸佛世尊，欲令眾生開佛知見，使得清淨故，出現於世；
欲示眾生佛之知見故，出現於世；
欲令眾生悟佛知見故，出現於世；
欲令眾生入佛知見道故，出現於世。舍利弗！是為諸佛以一大事因緣故出現於世。」
佛告舍利弗：「諸佛如來但教化菩薩，諸有所作，常為一事，唯以佛之知見示悟眾生。舍利弗！如來但以一佛乘故，為眾生說法，無有餘乘，若二、若三。舍利弗！一切十方諸佛，法亦如是。
「舍利弗！過去諸佛，以無量無數方便，種種因緣、譬喻言辭，而為眾生演說諸法，是法皆為一佛乘故。是諸眾生，從諸佛聞法，究竟皆得一切種智。
「舍利弗！未來諸佛當出於世，亦以無量無數方便，種種因緣、譬喻言辭，而為眾生演說諸法，是法皆為一佛乘故。是諸眾生，從佛聞法，究竟皆得一切種智。
「舍利弗！是諸佛但教化菩薩，欲以佛之知見示眾生故，欲以佛之知見悟眾生故，欲令眾生入佛之知見故。

「舍利弗！我今亦復如是，知諸眾生有種種欲，深心所著，隨其本性，以種種因緣、譬喻言辭，方便力而為說法。舍利弗！如此皆為得一佛乘、一切種智故。
「又，舍利弗！是諸比丘、比丘尼，自謂已得阿羅漢，是最後身，究竟涅槃，便不復志求阿耨多羅三藐三菩提，當知此輩皆是增上慢人。所以者何。若有比丘、實得阿羅漢，若不信此法，無有是處。除佛滅度後，現前無佛。所以者何？佛滅度後，如是等經受持讀誦解義者，是人難得。若遇餘佛，於此法中便得決了。舍利弗！汝等當一心信解受持佛語。諸佛如來言無虛妄，無有餘乘，唯一佛乘。」', '已發布'),
  (5, '大般涅槃經卷上', null, '爾時，世尊告諸比丘：「有四決定說。
一者若有比丘，樂欲說法，作如是言：『我親從佛聞如是法，善解其義，受持讀誦，極自通利。』汝等宜應請之令說，應隨所聞善自思惟，為修多羅，為是毘尼、法相之中，有此法耶？若修多羅及以毘尼法相之中，有此法者，宜應受持，稱讚善哉。若修多羅及以毘尼法相之中，無此法者，不應受持，亦勿稱讚，當知此法，非我所說。
二者若有比丘，樂欲說法，作如是言：『我於某處比丘僧眾，聞如是法，善解其義，受持讀誦，極自通利。』汝等宜應請之令說，隨所聞法善自思惟，為修多羅、為是毘尼、為是法相，有此法耶？若修多羅，及以毘尼、法相之中，有此法者，宜應受持，稱讚善哉。若修多羅及以毘尼、法相之中，無此法者，不應受持，亦勿稱讚。當知此法非我所說，亦復非彼比丘眾說。
三者若有比丘樂欲說法，作如是言：『我親從彼某僧伽藍某阿練若住處，眾多上座比丘，悉皆多聞，聰明智慧，聞如是法，善解其義，受持讀誦，極自通利。』汝等宜應請之令說，應隨所聞，善思惟之，為修多羅、為是毘尼、為是法相中有此法耶？若修多羅，及以毘尼、法相之中，有此法者，宜應受持，稱讚善哉。若修多羅及以毘尼、法相之中，無此法者，不應受持，亦勿稱讚。當知此法，非我所說。
四者若有比丘，樂欲說法，作如是言：『我親從某僧伽藍某阿練若住處，有一上座比丘，智慧多聞，聞如是法，善解其義，受持讀誦，極自通利。』汝等宜應請之令說，應隨所聞，善思惟之，為修多羅、為是毘尼、為法相中有此法耶？若修多羅及以毘尼、法相之中，有此法者，宜應受持，稱讚善哉。若修多羅及以毘尼、法相之中，無此法者，不應受持，亦勿稱讚。當知此法，非我所說，汝等宜應善分別此四決定說，又亦以此分別說法，傳授餘人。設我在世，及般涅槃，虛偽真實，以此知之。」時，諸比丘而白佛言：「善哉！世尊！我等從今當能分別佛說魔說。」', '已發布'),
  (6, '般泥洹經', null, '佛從定覺，自說頌曰：
佛為海船師　法橋渡河津
大乘道之典　一切渡天人
亦為自解脫　度岸得昇仙
都使諸弟子　縛解致泥洹

佛無上寶難可值遇
於生死海作大船師
憐愍眾生猶如赤子
法寶能為堅牢大船
渡生死海到彼岸故
永斷一切惡道怖畏
法為道藥多所療治
法為橋梁通諸往返
法為舟船度諸未度
佛治一切諸煩惱病
能救一切生死大苦
如來出世為大明燈
能破眾生無明黑闇
如來出世為大導師
引一切智安隱住處
譬如貧人得大伏藏
必斷一切煩惱惡業
不墮一切生死險道
如來出世為大醫王
能治眾生煩惱重病
皆悉巧黠無所不能
皆知天下諸所作為', '已發布'),
  (7, '佛說菩薩投身飴餓虎起塔因緣經', null, '於是太子在眾人前發大誓願：『我今捨身救眾生命，所有功德速成菩提，得金剛身、常樂我淨無為法身，未度者令度，未解者令解，未安者令安。又發誓言：『今我以肉血救彼餓虎。餘舍利骨，我父母後時必為起塔，令一切眾生身諸病苦、宿罪因緣、湯藥針灸不得差者，來我塔處至心供養，隨病輕重不過百日必得除愈', '已發布'),
  (8, '佛說長阿含經', null, '「佛告梵王：『如是！如是！如汝所言，但我於閑靜處默自思念：所得正法甚深微妙，若為彼說，彼必不解，更生觸擾，故我默然不欲說法。我從無數阿僧祇劫，勤苦不懈，修無上行，今始獲此難得之法，若為婬、怒、癡眾生說者，必不承用，徒自勞疲。此法微妙，與世相反，眾生染欲，愚冥所覆，不能信解。梵王！我觀如此，是以默然不欲說法。』', '已發布'),
  (9, '持人菩薩經卷第四', null, '「如是，阿難！諸族姓子訓立眾生，一切智安無上大道。
佛告阿難。佛無數劫億千兆載。合集積累是正法寶。其受是法族姓子等。十方無數不可計會。諸佛世尊遊無限土。今現在者咸共擁護。學是法者皆令安隱。佛言。阿難。天上世間。悉為是等諸族姓子。稽首敬禮歸命諮受。十方諸佛悉嗟嘆之。所演經法以示不逮。阿難。佛以豫印印是族姓決一切疑。若後末世受如是像無上正法。持諷誦說宣布同學。是族姓子及族姓女。以為疾近一切智業。臨法滅時聞是景摸深妙經法。懷喜信者。佛以授決行菩薩乘。如是至真。最後末世愛護是法。建立己身而愛樂法。佛以勸助。是諸族姓子及族姓女。而不誹謗斯深妙法。佛預授決諸聲聞乘。見彌勒佛出現於世。諸漏已盡無有愛欲。用受信是深妙法故。未曾誹謗致是功報。佛言。若菩薩學聞是深法信樂悅豫。亦皆授決。在於彌勒如來世時。出家學寂而復誓願。乃有殊特。佛謂。是族姓子女。德本調柔功勳無際。臨法欲沒最後末世。受斯深法奉行精進。德不可量巍巍如是。', '已發布'),
  (10, '陰持入經', null, '何等為入？解從是致名為入，從入解；譬從金入名為金地，從銀入名為銀地，如是各各應是譬喻所從所入，是從是有，如是從所意念，有行罪苦法如是。從所致，是名為從是入。亦有從是入，譬如王有入所有名，是亦如是。
為有四諦：苦、習、盡、道。苦名為要，語身亦念；習名為要，癡亦所世間愛；盡名為要，慧亦解脫；道名為要，止亦觀。
亦有三十七品經法：四意止、四意斷、四神足、五根、五力、七覺意、賢者八種道𧗪，是為三十七品經法。過去佛亦有是，現在佛亦有是，未來佛亦有是。辟支佛亦從是得度世道，佛弟子亦從是，是為度世無為道。', '已發布'),
  (11, '稱讚淨土佛攝受經', null, ' 「又，舍利子！極樂世界淨佛土中，周遍大地真金合成，其觸柔軟，香潔光明，無量無邊妙寶間飾。舍利子！彼佛土中有如是等眾妙綺飾，功德莊嚴甚可愛樂，是故名為極樂世界。
「又，舍利子！極樂世界淨佛土中，有如是等無量無邊不可思議甚希有事。假使經於百千俱胝那庾多劫，以其無量百千俱胝那庾多舌，一一舌上出無量聲讚其功德亦不能盡，是故名為極樂世界。
「又，舍利子！若諸有情聞彼西方無量壽佛清淨佛土無量功德眾所莊嚴，皆應發願生彼佛土。所以者何？若生彼土，得與如是無量功德眾所莊嚴諸大士等同一集會，受用如是無量功德眾所莊嚴清淨佛土，大乘法樂常無退轉，無量行願念念增進，速證無上正等菩提。故，舍利子！生彼佛土諸有情類成就無量無邊功德，非少善根諸有情類當得往生無量壽佛極樂世界清淨佛土。
「又，舍利子！我觀如是利益安樂大事因緣，說誠諦語。若有淨信諸善男子或善女人，得聞如是無量壽佛不可思議功德名號、極樂世界淨佛土者，一切皆應信受發願，如說修行，生彼佛土。
「又，舍利子！於此雜染堪忍世界五濁惡時，若有淨信諸善男子或善女人，聞說如是一切世間極難信法，能生信解、受持、演說、如教修行。當知是人甚為希有，無量佛所曾種善根。是人命終定生西方極樂世界，受用種種功德莊嚴清淨佛土大乘法樂，日夜六時親近供養無量壽佛，遊歷十方供養諸佛，於諸佛所聞法受記，福慧資糧疾得圓滿，速證無上正等菩提。」
以上節要取義，得聞無量壽佛不可思議功德名號、一切皆應信受發願，如說修行，生彼佛土。', '已發布'),
  (12, '佛說阿彌陀經', '姚秦龜茲三藏鳩摩羅什譯', '如是我聞：一時，佛在舍衛國祇樹給孤獨園，與大比丘僧千二百五十人俱，皆是大阿羅漢，眾所知識。長老舍利弗、摩訶目乾連、摩訶迦葉、摩訶迦栴延、摩訶拘絺羅、離婆多、周梨槃陀迦、難陀、阿難陀、羅睺羅、憍梵波提、賓頭盧頗羅墮、迦留陀夷、摩訶劫賓那、薄俱羅、阿㝹樓馱，如是等諸大弟子，并諸菩薩摩訶薩：文殊師利法王子、阿逸多菩薩、乾陀訶提菩薩、常精進菩薩，與如是等諸大菩薩，及釋提桓因等無量諸天大眾俱。
爾時，佛告長老舍利弗：「從是西方過十萬億佛土，有世界名曰極樂。其土有佛，號阿彌陀，今現在說法。舍利弗！彼土何故名為極樂？其國眾生無有眾苦，但受諸樂，故名極樂。又舍利弗！極樂國土，七重欄楯、七重羅網、七重行樹，皆是四寶周匝圍繞，是故彼國名曰極樂。
「又舍利弗！極樂國土有七寶池，八功德水充滿其中，池底純以金沙布地。四邊階道，金、銀、琉璃、頗梨合成。上有樓閣，亦以金、銀、琉璃、頗梨、車𤦲、赤珠、馬瑙而嚴飾之。池中蓮花，大如車輪，青色青光，黃色黃光，赤色赤光，白色白光，微妙香潔。舍利弗！極樂國土成就如是功德莊嚴。
「又舍利弗！彼佛國土，常作天樂，黃金為地，晝夜六時天雨曼陀羅華。其國眾生，常以清旦，各以衣裓盛眾妙華，供養他方十萬億佛；即以食時，還到本國，飯食經行。舍利弗！極樂國土成就如是功德莊嚴。
「復次舍利弗！彼國常有種種奇妙雜色之鳥：白鵠、孔雀、鸚鵡、舍利、迦陵頻伽、共命之鳥。是諸眾鳥，晝夜六時出和雅音，其音演暢五根、五力、七菩提分、八聖道分如是等法。其土眾生聞是音已，皆悉念佛、念法、念僧。舍利弗！汝勿謂：『此鳥實是罪報所生。』所以者何？彼佛國土無三惡趣。舍利弗！其佛國土尚無三惡道之名，何況有實？是諸眾鳥皆是阿彌陀佛欲令法音宣流變化所作。舍利弗！彼佛國土，微風吹動，諸寶行樹及寶羅網出微妙音，譬如百千種樂同時俱作，聞是音者皆自然生念佛、念法、念僧之心。舍利弗！其佛國土成就如是功德莊嚴。
「舍利弗！於汝意云何？彼佛何故號阿彌陀？舍利弗！彼佛光明無量，照十方國無所障礙，是故號為阿彌陀。又舍利弗！彼佛壽命及其人民，無量無邊阿僧祇劫，故名阿彌陀。舍利弗！阿彌陀佛成佛已來，於今十劫。又舍利弗！彼佛有無量無邊聲聞弟子，皆阿羅漢，非是算數之所能知；諸菩薩，亦復如是。舍利弗！彼佛國土，成就如是功德莊嚴。
「又舍利弗！極樂國土眾生生者，皆是阿鞞跋致。其中多有一生補處，其數甚多，非是算數所能知之，但可以無量無邊阿僧祇劫說。舍利弗！眾生聞者，應當發願，願生彼國。所以者何？得與如是諸上善人俱會一處。
「舍利弗！不可以少善根福德因緣，得生彼國。舍利弗！若有善男子、善女人，聞說阿彌陀佛，執持名號，若一日、若二日、若三日、若四日、若五日、若六日、若七日，一心不亂。其人臨命終時，阿彌陀佛與諸聖眾現在其前。是人終時，心不顛倒，即得往生阿彌陀佛極樂國土。舍利弗！我見是利，故說此言。若有眾生聞是說者，應當發願生彼國土。
「舍利弗！如我今者，讚歎阿彌陀佛不可思議功德；東方亦有阿閦鞞佛、須彌相佛、大須彌佛、須彌光佛、妙音佛，如是等恒河沙數諸佛，各於其國出廣長舌相，遍覆三千大千世界，說誠實言：『汝等眾生，當信是稱讚不可思議功德一切諸佛所護念經。』
「舍利弗！南方世界有日月燈佛、名聞光佛、大焰肩佛、須彌燈佛、無量精進佛，如是等恒河沙數諸佛，各於其國出廣長舌相，遍覆三千大千世界，說誠實言：『汝等眾生，當信是稱讚不可思議功德一切諸佛所護念經。』
「舍利弗！西方世界有無量壽佛、無量相佛、無量幢佛、大光佛、大明佛、寶相佛、淨光佛，如是等恒河沙數諸佛，各於其國出廣長舌相，遍覆三千大千世界，說誠實言：『汝等眾生，當信是稱讚不可思議功德一切諸佛所護念經。』
「舍利弗！北方世界有焰肩佛、最勝音佛、難沮佛、日生佛、網明佛，如是等恒河沙數諸佛，各於其國出廣長舌相，遍覆三千大千世界，說誠實言：『汝等眾生，當信是稱讚不可思議功德一切諸佛所護念經。』
「舍利弗！下方世界有師子佛、名聞佛、名光佛、達摩佛、法幢佛、持法佛，如是等恒河沙數諸佛，各於其國出廣長舌相，遍覆三千大千世界，說誠實言：『汝等眾生，當信是稱讚不可思議功德一切諸佛所護念經。』
「舍利弗！上方世界有梵音佛、宿王佛、香上佛、香光佛、大焰肩佛、雜色寶華嚴身佛、娑羅樹王佛、寶華德佛、見一切義佛、如須彌山佛，如是等恒河沙數諸佛，各於其國出廣長舌相，遍覆三千大千世界，說誠實言：『汝等眾生，當信是稱讚不可思議功德一切諸佛所護念經。』
「舍利弗！於汝意云何？何故名為『一切諸佛所護念經』？舍利弗！若有善男子、善女人，聞是經受持者，及聞諸佛名者；是諸善男子、善女人，皆為一切諸佛共所護念，皆得不退轉於阿耨多羅三藐三菩提。是故舍利弗！汝等皆當信受我語及諸佛所說。
「舍利弗！若有人已發願、今發願、當發願，欲生阿彌陀佛國者；是諸人等，皆得不退轉於阿耨多羅三藐三菩提，於彼國土若已生、若今生、若當生。是故舍利弗！諸善男子、善女人若有信者，應當發願生彼國土。
「舍利弗！如我今者，稱讚諸佛不可思議功德；彼諸佛等，亦稱說我不可思議功德，而作是言：『釋迦牟尼佛能為甚難希有之事，能於娑婆國土五濁惡世：劫濁、見濁、煩惱濁、眾生濁、命濁中，得阿耨多羅三藐三菩提，為諸眾生說是一切世間難信之法。』舍利弗！當知我於五濁惡世，行此難事；得阿耨多羅三藐三菩提，為一切世間說此難信之法，是為甚難！」
佛說此經已。舍利弗及諸比丘，一切世間天、人、阿修羅等，聞佛所說，歡喜信受，作禮而去。', '已發布'),
  (13, '佛說無量壽經卷上', '曹魏天竺三藏康僧鎧譯', '我聞如是：一時佛住王舍城耆闍崛山中，與大比丘眾萬二千人俱，一切大聖神通已達，其名曰：尊者了本際、尊者正願、尊者正語、尊者大號、尊者仁賢、尊者離垢、尊者名聞、尊者善實、尊者具足、尊者牛王、尊者優樓頻䗍迦葉、尊者伽耶迦葉、尊者那提迦葉、尊者摩訶迦葉、尊者舍利弗、尊者大目揵連、尊者劫賓那、尊者大住、尊者大淨志、尊者摩訶周那、尊者滿願子、尊者離障閡、尊者流灌、尊者堅伏、尊者面王、尊者果乘、尊者仁性、尊者喜樂、尊者善來、尊者羅云、尊者阿難，皆如斯等上首者也。
又與大乘眾菩薩俱，普賢菩薩、妙德菩薩、慈氏菩薩等，此賢劫中一切菩薩。
又賢護等十六正士：善思議菩薩、信慧菩薩、空無菩薩、神通華菩薩、光英菩薩、慧上菩薩、智幢菩薩、寂根菩薩、願慧菩薩、香象菩薩、寶英菩薩、中住菩薩、制行菩薩、解脫菩薩，皆遵普賢大士之德，具諸菩薩無量行願，安住一切功德之法，遊步十方，行權方便，入佛法藏，究竟彼岸，於無量世界現成等覺。
處兜率天弘宣正法，捨彼天宮降神母胎，從右脇生，現行七步。光明顯曜，普照十方無量佛土，六種振動，舉聲自稱：「吾當於世為無上尊，釋梵奉侍，天、人歸仰。」示現算計、文藝、射御，博綜道術，貫練群籍，遊於後園講武試藝。現處宮中色味之間，見老、病、死，悟世非常，棄國財位，入山學道，服乘、白馬、寶冠、瓔珞，遣之令還。捨珍妙衣而著法服，剃除鬚髮，端坐樹下。勤苦六年，行如所應。現五濁剎隨順群生，示有塵垢沐浴金流。天按樹枝得攀出池，靈禽翼從往詣道場，吉祥感徵表章功祚。哀受施草，敷佛樹下，加趺而坐，奮大光明使魔知之。魔率官屬而來逼試，制以智力皆令降伏，得微妙法成最正覺。釋梵祈勸請轉法輪，以佛遊步、佛吼而吼，扣法鼓、吹法螺、執法劍、建法幢、震法雷、曜法電、澍法雨、演法施，常以法音覺諸世間，光明普照無量佛土。一切世界六種震動，總攝魔界、動魔宮殿，眾魔懾怖莫不歸伏。摑裂邪網，消滅諸見，散諸塵勞，壞諸欲塹。嚴護法城，開闡法門；洗濯垢污，顯明清白；光融佛法，宣流正化。入國分衛獲諸豐饍，貯功德、示福田、欲宣法、現欣笑，以諸法藥救療三苦。顯現道意無量功德，授菩薩記成等正覺，示現滅度拯濟無極。消除諸漏，殖眾德本，具足功德微妙難量。遊諸佛國，普現道教，其所修行清淨無穢。
譬如幻師現眾異像，為男、為女無所不變，本學明了在意所為。此諸菩薩亦復如是，學一切法貫綜縷練，所住安諦靡不感化，無數佛土皆悉普現，未曾慢恣、愍傷眾生。如是之法一切具足，菩薩經典究暢要妙，名稱普至導御十方，無量諸佛咸共護念。佛所住者皆已得住、大聖所立而皆已立，如來導化各能宣布，為諸菩薩而作大師。以甚深禪慧開導眾人，通諸法性，達眾生相，明了諸國，供養諸佛。化現其身猶如電光，善學無畏曉了幻法。壞裂魔網，解諸纏縛。超越聲聞、緣覺之地，得空無相、無願三昧。善立方便，顯示三乘。於此中下而現滅度，亦無所作、亦無所有，不起、不滅得平等法。具足成就無量總持百千三昧，諸根智慧廣普寂定，深入菩薩法藏，得佛華嚴三昧。宣揚演說一切經典，住深定門，悉覩現在無量諸佛，一念之頃無不周遍。濟諸劇難諸閑不閑，分別顯示真實之際，得諸如來辯才之智。入眾言音，開化一切，超過世間諸所有法。心常諦住度世之道，於一切萬物隨意自在。為眾生類作不請之友，荷負群生為之重任。受持如來甚深法藏，護佛種性常使不絕。興大悲、愍眾生，演慈辯、授法眼、杜三趣、開善門，以不請之法施諸黎庶，猶如孝子愛敬父母。於諸眾生視之若己，一切善本皆度彼岸，悉獲諸佛無量功德，智慧聖明不可思議。
如是菩薩無量大士不可稱計，一時來會。
爾時，世尊諸根悅豫，姿色清淨，光顏巍巍。
尊者阿難承佛聖旨，即從座起，偏袒右肩，長跪合掌而白佛言：「今日世尊諸根悅豫，姿色清淨，光顏巍巍，如明鏡淨影暢表裏，威容顯耀超絕無量，未曾瞻覩殊妙如今。唯然，大聖！我心念言：『今日世尊住奇特法、今日世雄住佛所住、今日世眼住導師行、今日世英住最勝道、今日天尊行如來德。去來現在佛佛相念，得無今佛念諸佛耶？何故威神光光乃爾？』」
於是世尊告阿難曰：「云何，阿難！諸天教汝來問佛耶？自以慧見問威顏乎？」
阿難白佛：「無有諸天來教我者，自以所見問斯義耳。」
佛言：「善哉，阿難！所問甚快。發深智慧真妙辯才，愍念眾生問斯慧義。如來以無盡大悲矜哀三界，所以出興於世，光闡道教，普令群萌獲真法利。無量億劫難值難見，猶靈瑞華時時乃出。今所問者多所饒益，開化一切諸天人民。
「阿難！當知如來正覺其智難量，多所導御，慧見無礙，無能遏絕。以一喰之力，能住壽命億百千劫無數無量，復過於此。諸根悅豫不以毀損，姿色不變光顏無異。所以者何？如來定慧究暢無極，於一切法而得自在。
「阿難諦聽，今為汝說。」
對曰：「唯然，願樂欲聞。」
佛告阿難：「乃往過去久遠無量不可思議無央數劫，錠光如來興出於世，教化度脫無量眾生，皆令得道乃取滅度。次有如來名曰光遠、次名月光、次名栴檀香、次名善山王、次名須彌天冠、次名須彌等曜、次名月色、次名正念、次名離垢、次名無著、次名龍天、次名夜光、次名安明頂、次名不動地、次名琉璃妙華、次名琉璃金色、次名金藏、次名炎光、次名炎根、次名地種、次名月像、次名日音、次名解脫華、次名莊嚴光明、次名海覺神通、次名水光、次名大香、次名離塵垢、次名捨厭意、次名寶炎、次名妙頂、次名勇立、次名功德持慧、次名蔽日月光、次名日月琉璃光、次名無上琉璃光、次名最上首、次名菩提華、次名月明、次名日光、次名華色王、次名水月光、次名除癡冥、次名度蓋行、次名淨信、次名善宿、次名威神、次名法慧、次名鸞音、次名師子音、次名龍音、次名處世，如此諸佛皆悉已過。
「爾時，次有佛名世自在王如來、應供、等正覺、明行足、善逝、世間解、無上士、調御丈夫、天人師、佛、世尊。時有國王，聞佛說法心懷悅豫，尋發無上正真道意，棄國、捐王，行作沙門，號曰法藏，高才勇哲與世超異。詣世自在王如來所，稽首佛足，右遶三匝，長跪合掌以頌讚曰：
「『光顏巍巍　　威神無極　　如是炎明 　　無與等者　　日月摩尼　　珠光炎耀 　　皆悉隱蔽　　猶如聚墨　　如來容顏 　　超世無倫　　正覺大音　　響流十方 　　戒聞精進　　三昧智慧　　威德無侶 　　殊勝希有　　深諦善念　　諸佛法海 　　窮深盡奧　　究其崖底　　無明欲怒 　　世尊永無　　人雄師子　　神德無量 　　功德廣大　　智慧深妙　　光明威相 　　震動大千　　願我作佛　　齊聖法王 　　過度生死　　靡不解脫　　布施調意 　　戒忍精進　　如是三昧　　智慧為上 　　吾誓得佛　　普行此願　　一切恐懼 　　為作大安　　假令有佛　　百千億萬 　　無量大聖　　數如恒沙　　供養一切 　　斯等諸佛　　不如求道　　堅正不却 　　譬如恒沙　　諸佛世界　　復不可計 　　無數剎土　　光明悉照　　遍此諸國 　　如是精進　　威神難量　　令我作佛 　　國土第一　　其眾奇妙　　道場超絕 　　國如泥洹　　而無等雙　　我當愍哀 　　度脫一切　　十方來生　　心悅清淨 　　已到我國　　快樂安隱　　幸佛信明 　　是我真證　　發願於彼　　力精所欲 　　十方世尊　　智慧無礙　　常令此尊 　　知我心行　　假令身止　　諸苦毒中 　　我行精進　　忍終不悔
佛告阿難：「法藏比丘說此頌已而白佛言：『唯然，世尊！我發無上正覺之心，願佛為我廣宣經法，我當修行，攝取佛國清淨莊嚴無量妙土，令我於世速成正覺，拔諸生死勤苦之本。』」
佛語阿難：「時世自在王佛告法藏比丘：『如所修行莊嚴佛土，汝自當知。』
「比丘白佛：『斯義弘深，非我境界。唯願世尊廣為敷演諸佛如來淨土之行。我聞此已，當如說修行成滿所願。』
「爾時，世自在王佛知其高明志願深廣，即為法藏比丘而說經言：『譬如大海，一人斗量，經歷劫數尚可窮底，得其妙寶。人有至心，精進求道不止，會當剋果，何願不得？』
「於是，世自在王佛即為廣說二百一十億諸佛剎土天人之善惡、國土之粗妙，應其心願悉現與之。
「時彼比丘聞佛所說嚴淨國土，皆悉覩見。超發無上殊勝之願，其心寂靜，志無所著，一切世間無能及者。具足五劫，思惟攝取莊嚴佛國清淨之行。」
阿難白佛：「彼佛國土壽量幾何？」
佛言：「其佛壽命四十二劫。
「時法藏比丘攝取二百一十億諸佛妙土清淨之行。如是修已，詣彼佛所，稽首禮足，遶佛三匝，合掌而住，白言：『世尊！我已攝取莊嚴佛土清淨之行。』
「佛告比丘：『汝今可說，宜知是時。發起悅可一切大眾。菩薩聞已，修行此法，緣致滿足無量大願。』
「比丘白佛：『唯垂聽察，如我所願，當具說之。
「『設我得佛，國有地獄、餓鬼、畜生者，不取正覺。
「『設我得佛，國中人天壽終之後復更三惡道者，不取正覺。
「『設我得佛，國中人天不悉真金色者，不取正覺。
「『設我得佛，國中人天形色不同有好醜者，不取正覺。
「『設我得佛，國中人天不悉識宿命，下至知百千億那由他諸劫事者，不取正覺。
「『設我得佛，國中人天不得天眼，下至見百千億那由他諸佛國者，不取正覺。
「『設我得佛，國中人天不得天耳，下至聞百千億那由他諸佛所說不悉受持者，不取正覺。
「『設我得佛，國中人天不得見他心智，下至知百千億那由他諸佛國中眾生心念者，不取正覺。
「『設我得佛，國中人天不得神足於一念頃，下至不能超過百千億那由他諸佛國者，不取正覺。
「『設我得佛，國中人天若起想念貪計身者，不取正覺。
「『設我得佛，國中人天不住定聚必至滅度者，不取正覺。
「『設我得佛，光明有能限量，下至不照百千億那由他諸佛國者，不取正覺。
「『設我得佛，壽命有能限量，下至百千億那由他劫者，不取正覺。
「『設我得佛，國中聲聞有能計量，乃至三千大千世界眾生緣覺於百千劫悉共計挍知其數者，不取正覺。
「『設我得佛，國中人天壽命無能限量——除其本願脩短自在——若不爾者，不取正覺。
「『設我得佛，國中人天乃至聞有不善名者，不取正覺。
「『設我得佛，十方世界無量諸佛不悉諮嗟稱我名者，不取正覺。
「『設我得佛，十方眾生至心信樂欲生我國，乃至十念，若不生者，不取正覺，唯除五逆、誹謗正法。
「『設我得佛，十方眾生發菩提心修諸功德，至心發願欲生我國，臨壽終時，假令不與大眾圍遶現其人前者，不取正覺。
「『設我得佛，十方眾生聞我名號、係念我國，殖諸德本、至心迴向欲生我國，不果遂者，不取正覺。
「『設我得佛，國中人天不悉成滿三十二大人相者，不取正覺。
「『設我得佛，他方佛土諸菩薩眾來生我國，究竟必至一生補處——除其本願自在所化，為眾生故，被弘誓鎧，積累德本度脫一切；遊諸佛國修菩薩行，供養十方諸佛如來；開化恒沙無量眾生，使立無上正真之道；超出常倫諸地之行，現前修習普賢之德——若不爾者，不取正覺。
「『設我得佛，國中菩薩承佛神力供養諸佛，一食之頃不能遍至無量無數億那由他諸佛國者，不取正覺。
「『設我得佛，國中菩薩在諸佛前現其德本，諸所求欲供養之具若不如意者，不取正覺。
「『設我得佛，國中菩薩不能演說一切智者，不取正覺。
「『設我得佛，國中菩薩不得金剛那羅延身者，不取正覺。
「『設我得佛，國中人、天、一切萬物嚴淨光麗，形色殊特，窮微極妙，無能稱量。其諸眾生乃至逮得天眼，有能明了辨其名數者，不取正覺。
「『設我得佛，國中菩薩乃至少功德者，不能知見其道場樹無量光色高四百萬里者，不取正覺。
「『設我得佛，國中菩薩若受讀經法，諷誦持說而不得辯才智慧者，不取正覺。
「『設我得佛，國中菩薩智慧辯才若可限量者，不取正覺。
「『設我得佛，國土清淨，皆悉照見十方一切無量無數不可思議諸佛世界，猶如明鏡覩其面像；若不爾者，不取正覺。
「『設我得佛，自地以上至于虛空，宮殿、樓觀、池流、華樹——國土所有一切萬物——皆以無量雜寶百千種香而共合成，嚴飾奇妙超諸人天，其香普薰十方世界，菩薩聞者皆修佛行；若不爾者，不取正覺。
「『設我得佛，十方無量不可思議諸佛世界眾生之類，蒙我光明觸其體者，身心柔軟超過人天；若不爾者，不取正覺。
「『設我得佛，十方無量不可思議諸佛世界眾生之類，聞我名字不得菩薩無生法忍、諸深總持者，不取正覺。
「『設我得佛，十方無量不可思議諸佛世界，其有女人聞我名字，歡喜信樂，發菩提心，厭惡女身，壽終之後復為女像者，不取正覺。
「『設我得佛，十方無量不可思議諸佛世界，諸菩薩眾聞我名字，壽終之後常修梵行至成佛道；若不爾者，不取正覺。
「『設我得佛，十方無量不可思議諸佛世界，諸天人民聞我名字，五體投地稽首作禮，歡喜信樂修菩薩行，諸天世人莫不致敬；若不爾者，不取正覺。
「『設我得佛，國中人天欲得衣服隨念即至，如佛所讚應法妙服自然在身；若有裁縫、染治、浣濯者，不取正覺。
「『設我得佛，國中人天所受快樂不如漏盡比丘者，不取正覺。
「『設我得佛，國中菩薩隨意欲見十方無量嚴淨佛土，應時如願，於寶樹中皆悉照見，猶如明鏡覩其面像；若不爾者，不取正覺。
「『設我得佛，他方國土諸菩薩眾聞我名字，至于得佛，諸根缺陋不具足者，不取正覺。
「『設我得佛，他方國土諸菩薩眾聞我名字，皆悉逮得清淨解脫三昧，住是三昧一發意頃，供養無量不可思議諸佛世尊而不失定意；若不爾者，不取正覺。
「『設我得佛，他方國土諸菩薩眾聞我名字，壽終之後生尊貴家；若不爾者，不取正覺。
「『設我得佛，他方國土諸菩薩眾聞我名字，歡喜踊躍，修菩薩行，具足德本；若不爾者，不取正覺。
「『設我得佛，他方國土諸菩薩眾聞我名字，皆悉逮得普等三昧，住是三昧至于成佛，常見無量不可思議一切如來；若不爾者，不取正覺。
「『設我得佛，國中菩薩隨其志願，所欲聞法自然得聞；若不爾者，不取正覺。
「『設我得佛，他方國土諸菩薩眾聞我名字，不即得至不退轉者，不取正覺。
「『設我得佛，他方國土諸菩薩眾聞我名字，不即得至第一、第二、第三法忍，於諸佛法不能即得不退轉者，不取正覺。』」
佛告阿難：「爾時，法藏比丘說此願已，而說頌曰：
「『我建超世願　　必至無上道 　　斯願不滿足  　誓不成等覺 　　我於無量劫　　不為大施主 　　普濟諸貧苦　　誓不成等覺 　　我至成佛道　　名聲超十方 　　究竟靡不聞　　誓不成等覺 　　離欲深正念　　淨慧修梵行 　　志求無上道　　為諸天人師 　　神力演大光　　普照無際土 　　消除三垢冥　　明濟眾厄難 　　開彼智慧眼　　滅此昏盲闇 　　閉塞諸惡道　　通達善趣門 　　功祚成滿足　　威曜朗十方 　　日月戢重暉　　天光隱不現 　　為眾開法藏　　廣施功德寶 　　常於大眾中　　說法師子吼 　　供養一切佛　　具足眾德本 　　願慧悉成滿　　得為三界雄 　　如佛無量智　　通達靡不遍 　　願我功德力　　等此最勝尊 　　斯願若剋果　　大千應感動 　　虛空諸天人　　當雨珍妙華
佛語阿難：「法藏比丘說此頌已，應時普地六種震動，天雨妙華以散其上，自然音樂空中讚言：『決定必成無上正覺。』於是法藏比丘具足修滿如是大願，誠諦不虛，超出世間深樂寂滅。
「阿難！法藏比丘於彼佛所諸天、魔、梵、龍神八部大眾之中發斯弘誓，建此願已，一向專志莊嚴妙土。所修佛國開廓廣大，超勝獨妙，建立常然，無衰、無變。於不可思議兆載永劫積殖菩薩無量德行，不生欲覺、瞋覺、害覺，不起欲想、瞋想、害想，不著色、聲、香、味、觸之法。忍力成就，不計眾苦。少欲知足，無染恚癡，三昧常寂，智慧無礙。無有虛偽諂曲之心，和顏軟語先意承問，勇猛精進志願無]惓，專求清白之法。以慧利群生，恭敬三寶，奉事師長；以大莊嚴具足眾行，令諸眾生功德成就。住空、無相、無願之法，無作、無起，觀法如化。遠離麁言、自害、害彼、彼此俱害，修習善語，自利、利人、彼我兼利。棄國、捐王，絕去財色。自行六波羅蜜，教人令行。
「無央數劫積功累德，隨其生處在意所欲，無量寶藏自然發應，教化安立無數眾生。住於無上正真之道，或為長者、居士、豪姓、尊貴，或為剎利國君、轉輪聖帝，或為六欲天主乃至梵王。常以四事供養恭敬一切諸佛，如是功德不可稱說。口氣香潔如優鉢羅華，身諸毛孔出栴檀香，其香普熏無量世界；容色端正，相好殊妙，其手常出無盡之寶，衣服、飲食珍妙華香，諸蓋幢幡莊嚴之具。如是等事超諸人天，於一切法而得自在。」
阿難白佛：「法藏菩薩為已成佛而取滅度、為未成佛？為今現在？」
佛告阿難：「法藏菩薩今已成佛，現在西方，去此十萬億剎，其佛世界名曰安樂。」
阿難又問：「其佛成道已來為經幾時？」
佛言：「成佛已來凡歷十劫。其佛國土自然七寶——金、銀、琉璃、珊瑚、琥珀、車𤦲、瑪瑙——合成為地，恢廓曠蕩不可限極。悉相雜廁，轉相入間，光赫焜耀，微妙奇麗，清淨莊嚴超踰十方一切世界眾寶中精，其寶猶如第六天寶。又其國土無須彌山及金剛圍一切諸山，亦無大海、小海、溪渠、井谷。佛神力故，欲見則見。亦無地獄、餓鬼、畜生諸難之趣。亦無四時——春、秋、冬、夏——不寒、不熱，常和調適。」
爾時，阿難白佛言：「世尊！若彼國土無須彌山，其四天王及忉利天依何而住？」
佛語阿難：「第三炎天乃至色究竟天皆依何住？」
阿難白佛：「行業果報不可思議。」
佛語阿難：「行業果報不可思議，諸佛世界亦不可思議。其諸眾生功德善力住行業之地，故能爾耳。」
阿難白佛：「我不疑此法，但為將來眾生欲除其疑惑，故問斯義。」
佛告阿難：「無量壽佛威神光明最尊第一，諸佛光明所不能及。或有佛光照百佛世界、或千佛世界，取要言之，乃照東方恒沙佛剎，南、西、北方四維，上、下亦復如是。或有佛光照于七尺，或照一由旬，二、三、四、五由旬，如是轉倍乃至照一佛剎。是故，無量壽佛號無量光佛、無邊光佛、無礙光佛、無對光佛、炎王光佛、清淨光佛、歡喜光佛、智慧光佛、不斷光佛、難思光佛、無稱光佛、超日月光佛。
「其有眾生遇斯光者，三垢消滅，身意柔軟，歡喜踊躍，善心生焉。若在三塗勤苦之處，見此光明，皆得休息，無復苦惱；壽終之後皆蒙解脫。
「無量壽佛光明顯赫照曜十方諸佛國土，莫不聞知。不但我今稱其光明，一切諸佛、聲聞、緣覺、諸菩薩眾咸共歎譽，亦復如是。若有眾生聞其光明威神功德，日夜稱說至心不斷，隨意所願得生其國，為諸菩薩、聲聞大眾所共歎譽稱其功德；至其然後得佛道時，普為十方諸佛菩薩歎其光明亦如今也。」
佛言：「我說無量壽佛光明威神巍巍殊妙，晝夜一劫尚不能盡。」
佛語阿難：「無量壽佛壽命長久不可稱計，汝寧知乎？假使十方世界無量眾生皆得人身，悉令成就聲聞、緣覺，都共集會禪思一心，竭其智力於百千萬劫悉共推算，計其壽命長遠劫數，不能窮盡知其限極。聲聞、菩薩、天、人之眾，壽命長短亦復如是，非算數譬喻所能知也。又聲聞、菩薩其數難量不可稱說，神智洞達威力自在，能於掌中持一切世界。」
佛語阿難：「彼佛初會，聲聞眾數不可稱計，菩薩亦然。能如大目揵連百千萬億無量無數，於阿僧祇那由他劫乃至滅度悉共計挍，不能究了多少之數。譬如大海深廣無量，假使有人析其一毛以為百分，以一分毛沾取一渧。於意云何？其所渧者於彼大海，何所為多？」
阿難白佛：「彼所渧水比於大海多少之量，非巧歷算數、言辭譬類所能知也。」
佛語阿難：「如目連等於百千萬億那由他劫計彼初會聲聞菩薩，所知數者猶如一渧，其所不知如大海水。
「又其國土，七寶諸樹周滿世界——金樹、銀樹、琉璃樹、頗梨樹、珊瑚樹、瑪瑙樹、車磲樹——或有二寶、三寶乃至七寶轉共合成。或有金樹，銀葉、華、果；或有銀樹，金葉、華、果；或琉璃樹，玻梨為葉，華、果亦然；或水精樹，琉璃為葉，華、果亦然；或珊瑚樹，瑪瑙為葉，華、果亦然；或瑪瑙樹，琉璃為葉，華、果亦然；或車磲樹，眾寶為葉，華、果亦然。或有寶樹，紫金為本、白銀為莖、琉璃為枝、水精為條、珊瑚為葉、瑪瑙為華、車磲為實；或有寶樹，白銀為本、琉璃為莖、水精為枝、珊瑚為條、瑪瑙為葉、車磲為華、紫金為實；或有寶樹，琉璃為本、水精為莖、珊瑚為枝、瑪瑙為條、車磲為葉、紫金為華、白銀為實；或有寶樹，水精為本、珊瑚為莖、瑪瑙為枝、車磲為條、紫金為葉、白銀為華、琉璃為實；或有寶樹，珊瑚為本、瑪瑙為莖、車磲為枝、紫金為條、白銀為葉、琉璃為華、水精為實；或有寶樹，瑪瑙為本、車磲為莖、紫金為枝、白銀為條、琉璃為葉、水精為華、珊瑚為實；或有寶樹，車磲為本、紫金為莖、白銀為枝、琉璃為條、水精為葉、珊瑚為華、瑪瑙為實。行行相值、莖莖相望、枝枝相準、葉葉相向、華華相順、實實相當，榮色光曜不可勝視。清風時發，出五音聲，微妙宮商自然相和。
「又無量壽佛其道場樹，高四百萬里，其本周圍五千由旬，枝葉四布二十萬里。一切眾寶自然合成，以月光摩尼持海輪寶——眾寶之王——而莊嚴之。周匝條間垂寶瓔珞，百千萬色種種異變，無量光炎照曜無極。珍妙寶網羅覆其上，一切莊嚴隨應而現。微風徐動出妙法音，普流十方一切佛國。其聞音者得深法忍，住不退轉至成佛道，不遭苦患；目覩其色、耳聞其音、鼻知其香、舌甞其味、身觸其光、心以法緣，一切皆得甚深法忍，住不退轉至成佛道，六根清徹無諸惱患。
「阿難！若彼國人天見此樹者，得三法忍：一者、音響忍，二者、柔順忍，三者、無生法忍。此皆無量壽佛威神力故、本願力故、滿足願故、明了願故、堅固願故、究竟願故。」
佛告阿難：「世間帝王有百千音樂，自轉輪聖王乃至第六天上，伎樂音聲展轉相勝千億萬倍；第六天上萬種樂音，不如無量壽國諸七寶樹一種音聲千億倍也。亦有自然萬種伎樂，又其樂聲無非法音，清暢哀亮，微妙和雅，十方世界音聲之中最為第一。
「又，講堂、精舍、宮殿、樓觀皆七寶莊嚴，自然化成，復以真珠、明月摩尼眾寶以為交露，覆蓋其上。內、外、左、右有諸浴池，或十由旬，或二十、三十，乃至百千由旬，縱廣深淺各皆一等，八功德水湛然盈滿，清淨香潔味如甘露。黃金池者底白銀沙，白銀池者底黃金沙，水精池者底琉璃沙，琉璃池者底水精沙，珊瑚池者底琥珀沙，琥珀池者底珊瑚沙，車磲池者底瑪瑙沙，瑪瑙池者底車磲沙，白玉池者底紫金沙，紫金池者底白玉沙，或二寶、三寶乃至七寶轉共合成。其池岸上有栴檀樹，華葉垂布，香氣普熏。天優鉢羅華、鉢曇摩華、拘物頭華、分陀利華，雜色光茂彌覆水上。
「彼諸菩薩及聲聞眾若入寶池，意欲令水沒足，水即沒足；欲令至膝，即至于膝；欲令至腰，水即至腰；欲令至頸，水即至頸；欲令灌身，自然灌身；欲令還復，水輒還復。調和冷煖自然隨意，開神悅體蕩除心垢，清明澄潔淨若無形。寶沙映徹無深不照，微瀾迴流轉相灌注，安詳徐逝不遲不疾。波揚無量自然妙聲，隨其所應莫不聞者，或聞佛聲，或聞法聲，或聞僧聲，或寂靜聲、空無我聲、大慈悲聲、波羅蜜聲，或十力無畏不共法聲、諸通慧聲、無所作聲、不起滅聲、無生忍聲，乃至甘露灌頂眾妙法聲。如是等聲，稱其所聞歡喜無量，隨順清淨離欲寂滅真實之義、隨順三寶力無所畏不共之法、隨順通慧菩薩聲聞所行之道。無有三塗苦難之名，但有自然快樂之音，是故其國名曰極樂。
「阿難！彼佛國土諸往生者，具足如是清淨色身、諸妙音聲、神通功德，所處宮殿、衣服、飲食、眾妙華香莊嚴之具，猶第六天自然之物。若欲食時，七寶應器自然在前，金、銀、琉璃、車磲、瑪瑙、珊瑚、虎珀、明月真珠如是眾鉢隨意而至，百味飲食自然盈滿。雖有此食實無食者，但見色、聞香，意以為食，自然飽足，身心柔軟，無所味著。事已化去，時至復現。
「彼佛國土清淨安隱，微妙快樂，次於無為泥洹之道。其諸聲聞、菩薩、人、天，智慧高明，神通洞達。咸同一類，形無異狀，但因順餘方，故有人、天之名。顏貌端正，超世希有，容色微妙，非天、非人，皆受自然虛無之身、無極之體。」
佛告阿難：「譬如世間貧窮乞人在帝王邊，形貌容狀寧可類乎？」
阿難白佛：「假令此人在帝王邊，羸陋醜惡無以為喻，百千萬億不可計倍。所以然者？貧窮乞人底極廝下，衣不蔽形，食趣支命，飢寒困苦，人理殆盡。皆坐前世不殖德本，積財不施、富有益慳，但欲唐得、貪求無厭，不信修善、犯惡山積。如是壽終，財寶消散，苦身積聚為之憂惱，於己無益，徒為他有。無善可怙，無德可恃，是故，死墮惡趣，受此長苦。罪畢得出生為下賤，愚鄙斯極示同人類。所以世間帝王人中獨尊，皆由宿世積德所致，慈惠博施，仁愛兼濟，履信修善，無所違諍。是以壽終，福應得昇善道，上生天上享茲福樂。積善餘慶今得為人，遇生王家自然尊貴，儀容端正眾所敬事，妙衣珍膳隨心服御。宿福所追，故能致此。」
佛告阿難：「汝言是也。計如帝王，雖人中尊貴，形色端正，比之轉輪聖王，甚為鄙陋，猶彼乞人在帝王邊。轉輪聖王威相殊妙天下第一，比忉利天王，又復醜惡不得相喻萬億倍也。假令天帝比第六天王，百千億倍不相類也。設第六天王比無量壽佛國菩薩、聲聞，光顏容色不相及逮，百千萬億不可計倍。」
佛告阿難：「無量壽國其諸天人，衣服、飲食、華香、瓔珞、諸蓋幢幡、微妙音聲，所居舍宅、宮殿、樓閣，稱其形色、高下、大小，或一寶、二寶，乃至無量眾寶，隨意所欲，應念即至。又，以眾寶妙衣遍布其地，一切人天踐之而行。無量寶網彌覆佛上，皆以金縷、真珠、百千雜寶、奇妙珍異莊嚴絞飾，周匝四面垂以寶鈴，光色晃曜盡極嚴麗。自然德風徐起微動，其風調和，不寒、不暑；溫涼柔軟，不遲、不疾；吹諸羅網及眾寶樹，演發無量微妙法音，流布萬種溫雅德香。其有聞者，塵勞垢習自然不起，風觸其身皆得快樂，譬如比丘得滅盡三昧。
「又，風吹散華遍滿佛土，隨色次第而不雜亂，柔軟光澤馨香芬烈，足履其上陷下四寸，隨舉足已還復如故。華用已訖地輒開裂，以次化沒清淨無遺，隨其時節風吹散華，如是六反。
「又眾寶蓮華周滿世界，一一寶華百千億葉，其葉光明無量種色，青色青光、白色白光、玄黃、朱紫光色亦然，煒燁煥爛，明曜日月。一一華中出三十六百千億光；一一光中出三十六百千億佛，身色紫金，相好殊特；一一諸佛又放百千光明，普為十方說微妙法；如是諸佛各各安立無量眾生於佛正道。」', '已發布'),
  (14, '佛說無量壽經卷下', '曹魏天竺三藏康僧鎧譯', '佛告阿難：「其有眾生生彼國者，皆悉住於正定之聚。所以者何？彼佛國中無諸邪聚及不定之聚，十方恒沙諸佛如來皆共讚歎無量壽佛威神功德不可思議。諸有眾生聞其名號信心歡喜，乃至一念，至心迴向願生彼國，即得往生住不退轉，唯除五逆、誹謗正法。」
佛告阿難：「十方世界諸天人民，其有至心願生彼國，凡有三輩。其上輩者，捨家棄欲而作沙門，發菩提心，一向專念無量壽佛，修諸功德願生彼國。此等眾生臨壽終時，無量壽佛與諸大眾現其人前，即隨彼佛往生其國，便於七寶華中自然化生，住不退轉，智慧勇猛，神通自在。是故，阿難！其有眾生欲於今世見無量壽佛，應發無上菩提之心，修行功德，願生彼國。」
佛語阿難：「其中輩者，十方世界諸天人民，其有至心願生彼國，雖不能行作沙門大修功德，當發無上菩提之心，一向專念無量壽佛。多少修善、奉持齋戒、起立塔像、飯食沙門、懸繒然燈、散華燒香，以此迴向願生彼國。其人臨終，無量壽佛化現其身——光明相好，具如真佛——與諸大眾現其人前，即隨化佛往生其國，住不退轉，功德智慧次如上輩者也。」
佛語阿難：「其下輩者，十方世界諸天人民，其有至心欲生彼國，假使不能作諸功德，當發無上菩提之心，一向專意乃至十念，念無量壽佛，願生其國。若聞深法歡喜信樂，不生疑惑，乃至一念念於彼佛，以至誠心願生其國。此人臨終夢見彼佛，亦得往生，功德智慧次如中輩者也。」
佛告阿難：「無量壽佛威神無極，十方世界無量無邊不可思議諸佛如來莫不稱歎。於彼東方恒沙佛國，無量無數諸菩薩眾，皆悉往詣無量壽佛所恭敬供養，及諸菩薩、聲聞大眾聽受經法，宣布道化；南、西、北方、四維，上、下亦復如是。」
爾時，世尊而說頌曰：
「東方諸佛國　　其數如恒沙 　彼土諸菩薩　　往覲無量覺 　南西北四維　　上下亦復然 　彼土菩薩眾　　往覲無量覺 　一切諸菩薩　　各齎天妙華 　寶香無價衣　　供養無量覺 　咸然奏天樂　　暢發和雅音 　歌歎最勝尊　　供養無量覺 　究達神通慧　　遊入深法門 　具足功德藏　　妙智無等倫 　慧日照世間　　消除生死雲 　恭敬遶三匝　　稽首無上尊 　見彼嚴淨土　　微妙難思議 　因發無量心　　願我國亦然 　應時無量尊　　動容發欣笑 　口出無數光　　遍照十方國 　迴光圍遶身　　三匝從頂入 　一切天人眾　　踊躍皆歡喜 　大士觀世音　　整服稽首問 　白佛何緣笑　　唯然願說意 　梵聲猶雷震　　八音暢妙響   當授菩薩記　　今說仁諦聽 　十方來正士　　吾悉知彼願 　志求嚴淨土　　受決當作佛 　覺了一切法　　猶如夢幻響 　滿足諸妙願　　必成如是剎 　知法如電影　　究竟菩薩道 　具諸功德本　　受決當作佛 　通達諸法門　　一切空無我 　專求淨佛土　　必成如是剎 　諸佛告菩薩　　令覲安養佛 　聞法樂受行　　疾得清淨處 　至彼嚴淨土　　便速得神通 　必於無量尊　　受記成等覺 　其佛本願力　　聞名欲往生 　皆悉到彼國　　自致不退轉 　菩薩興志願　　願己國無異 　普念度一切　　名顯達十方 　奉事億如來　　飛化遍諸剎 　恭敬歡喜去　　還到安養國 　若人無善本　　不得聞此經 　清淨有戒者　　乃獲聞正法 　曾更見世尊　　則能信此事 　謙敬聞奉行　　踊躍大歡喜 　憍慢弊懈怠　　難以信此法 　宿世見諸佛　　樂聽如是教 　聲聞或菩薩　　莫能究聖心 　譬如從生盲　　欲行開導人 　如來智慧海　　深廣無崖底 　二乘非所測　　唯佛獨明了 　假使一切人　　具足皆得道 　淨慧如本空　　億劫思佛智 　窮力極講說　　盡壽猶不知 　佛慧無邊際　　如是致清淨 　壽命甚難得　　佛世亦難值 　人有信慧難　　若聞精進求 　聞法能不忘　　見敬得大慶 　則我善親友　　是故當發意 　設滿世界火　　必過要聞法 　會當成佛道　　廣濟生死流
佛告阿難：「彼國菩薩皆當究竟一生補處——除其本願為眾生故——以弘誓功德而自莊嚴，普欲度脫一切眾生。阿難！彼佛國中諸聲聞眾身光一尋，菩薩光明照百由旬。有二菩薩最尊第一，威神光明普照三千大千世界。」
阿難白佛：「彼二菩薩其號云何？」
佛言：「一名觀世音，二名大勢至。是二菩薩於此國土修菩薩行，命終轉化生彼佛國。阿難！其有眾生生彼國者，皆悉具足三十二相，智慧成滿，深入諸法，究暢要妙，神通無礙，諸根明利。其鈍根者成就二忍，其利根者得阿僧祇無生法忍。又彼菩薩乃至成佛不更惡趣，神通自在常識宿命，除生他方五濁惡世，示現同彼如我國也。」
佛語阿難：「彼國菩薩承佛威神，一食之頃往詣十方無量世界，恭敬供養諸佛世尊，隨心所念，華香、伎樂、繒蓋、幢幡，無數無量供養之具自然化生，應念即至，珍妙殊特非世所有。轉以奉散諸佛、菩薩、聲聞大眾，在虛空中化成華蓋，光色晃耀，香氣普熏。其華周圓四百里者，如是轉倍，乃覆三千大千世界，隨其前後以次化沒。其諸菩薩僉然欣悅，於虛空中共奏天樂，以微妙音歌歎佛德，聽受經法歡喜無量。供養佛已、未食之前，忽然輕舉還其本國。」
佛語阿難：「無量壽佛為諸聲聞、菩薩大眾頒宣法時，都悉集會七寶講堂，廣宣道教，演暢妙法，莫不歡喜，心解得道。即時四方自然風起，普吹寶樹出五音聲，雨無量妙華隨風周遍，自然供養如是不絕。一切諸天皆齎天上百千華香、萬種伎樂供養其佛及諸菩薩、聲聞大眾，普散華香、奏諸音樂，前後來往更相開避。當斯之時，熙然快樂不可勝言。」
佛告阿難：「生彼佛國諸菩薩等，所可講說常宣正法，隨順智慧無違無失。於其國土所有萬物，無我所心、無染著心，去來進止情無所係，隨意自在無所適莫，無彼、無我，無競、無訟。於諸眾生得大慈悲饒益之心、柔軟調伏無忿恨心、離蓋清淨無厭怠心、等心、勝心、深心、定心、愛法樂法喜法之心、滅諸煩惱離惡趣心，究竟一切菩薩所行，具足成就無量功德，得深禪定諸通明慧，遊志七覺修心佛法，肉眼清徹靡不分了、天眼通達無量無限、法眼觀察究竟諸道、慧眼見真能度彼岸、佛眼具足覺了法性。以無礙智為人演說，等觀三界空無所有，志求佛法具諸辯才，除滅眾生煩惱之患。從如來生，解法如如，善知習滅，音聲方便。不欣世語，樂在正論，修諸善本，志崇佛道。知一切法皆悉寂滅，生身煩惱二餘俱盡。聞甚深法心不疑懼，常能修行其大悲者。深遠微妙靡不覆載，究竟一乘至于彼岸。決斷疑網，慧由心出，於佛教法該羅無外。智慧如大海、三昧如山王，慧光明淨超踰日月，清白之法具足圓滿。
「猶如雪山，照諸功德等一淨故；猶如大地，淨穢好惡無異心故；猶如淨水，洗除塵勞諸垢染故；猶如火王，燒滅一切煩惱薪故；猶如大風，行諸世界無障閡故；猶如虛空，於一切有無所著故；猶如蓮華，於諸世間無染污故；猶如大乘，運載群萌出生死故；猶如重雲，震大法雷覺未覺故；猶如大雨，雨甘露法潤眾生故；如金剛山，眾魔外道不能動故；如梵天王，於諸善法最上首故；如尼拘類樹，普覆一切故；如優曇鉢華，希有難遇故；如金翅鳥，威伏外道故；如眾遊禽，無所藏積故；猶如牛王，無能勝故；猶如象王，善調伏故；如師子王，無所畏故。
「曠若虛空，大慈等故；摧滅嫉心，不望勝故。專樂求法，心無厭足；常欲廣說，志無疲倦。擊法鼓、建法幢、曜慧日、除癡闇、修六和敬、常行法施，志勇精進，心不退弱。為世燈明、最勝福田，常為師導等無憎愛。唯樂正道無餘欣慼，拔諸欲刺以安群生，功德殊勝莫不尊敬，滅三垢障遊諸神通。因力、緣力、意力、願力、方便之力、常力、善力、定力、慧力、多聞之力、施戒、忍辱、精進、禪定、智慧之力、正念止觀諸通明力、如法調伏諸眾生力，如是等力一切具足。身色相好，功德、辯才具足莊嚴，無與等者。恭敬供養無量諸佛，常為諸佛所共稱歎。究竟菩薩諸波羅蜜，修空無相無願三昧、不生不滅諸三昧門，遠離聲聞緣覺之地。
「阿難！彼諸菩薩成就如是無量功德，我但為汝略言之耳；若廣說者，百千萬劫不能窮盡。」
佛告彌勒菩薩、諸天、人等：「無量壽國聲聞、菩薩功德智慧不可稱說，又其國土微妙安樂清淨若此，何不力為善，念道之自然，著於無上下，洞達無邊際？宜各勤精進，努力自求之，必得超絕去，往生安養國。橫截五惡趣，惡趣自然閉；昇道無窮極，易往而無人。其國不逆違，自然之所牽，何不棄世事，勤行求道德，可獲極長生，壽樂無有極？
「然世人薄俗，共諍不急之事。於此劇惡極苦之中，勤身營務以自給濟。無尊、無卑，無貧、無富，少、長、男、女共憂錢財，有無同然，憂思適等。屏營愁苦，累念積慮，為心走使，無有安時——有田憂田、有宅憂宅，牛、馬、六畜、奴婢、錢財、衣、食、什物，復共憂之——重思累息，憂念愁怖，橫為非常、水、火、盜賊、怨家、債主焚漂劫奪，消散磨滅，憂毒忪忪，無有解時。結憤心中不離憂惱，心堅意固適無縱捨，或坐摧碎身亡命終，棄捐之去莫誰隨者。
「尊貴、豪富亦有斯患，憂懼萬端，勤苦若此，結眾寒熱與痛共俱。貧窮下劣困乏常無，無田亦憂欲有田、無宅亦憂欲有宅，無牛、馬、六畜、奴婢、錢財、衣、食、什物亦憂欲有之。適有一復少一、有是少是，思有齊等；適欲具有便復糜散。如是憂苦當復求索，不能時得思想無益，身心俱勞，坐起不安，憂念相隨，勤苦若此，亦結眾寒熱與痛共俱。或時坐之終身夭命，不肯為善、行道、進德，壽終身死當獨遠去，有所趣向善惡之道，莫能知者。
「世間人民，父子、兄弟、夫婦、家室、中外親屬，當相敬愛，無相憎嫉；有無相通，無得貪惜；言色常和，莫相違戾。或時心諍有所恚怒，今世恨意微相憎嫉，後世轉劇至成大怨。所以者何？世間之事更相患害，雖不即時應急相破，然含毒畜怒結憤精神，自然剋識不得相離，皆當對生更相報復。人在世間愛欲之中，獨生、獨死，獨去、獨來，當行至趣苦樂之地，身自當之無有代者。善惡變化、殃福異處，宿豫嚴待，當獨趣入。遠到他所莫能見者，善惡自然追行所生。窈窈冥冥別離久長，道路不同會見無期，甚難甚難復得相值。何不棄眾事，各曼強健時，努力勤修善，精進願度世，可得極長生？如何不求道，安所須待，欲何樂乎？
「如是，世人不信作善得善、為道得道，不信人死更生、惠施得福，善惡之事都不信之，謂之不然終無有是。但坐此故，且自見之，更相瞻視，先後同然。轉相承受父餘教令，先人祖父素不為善、不識道德，身愚神闇，心塞意閉。死生之趣、善惡之道，自不能見，無有語者；吉凶禍福，競各作之，無一怪也。生死常道轉相嗣立，或父哭子、或子哭父，兄弟、夫婦更相哭泣，顛倒上下無常根本，皆當過去不可常保。教語開導，信之者少，是以生死流轉無有休止。
「如此之人，曚冥抵突，不信經法，心無遠慮，各欲快意；癡惑於愛欲，不達於道德；迷沒於瞋怒，貪狼於財色。坐之不得道，當更惡趣苦，生死無窮已，哀哉甚可傷。或時室家，父子、兄弟、夫婦，一死一生更相哀愍，恩愛、思慕、憂念結縛，心意痛著迭相顧戀，窮日卒歲無有解已。教語道德心不開明，思想恩好不離情欲。惛曚閉塞，愚惑所覆，不能深思熟計、心自端政、專精行道、決斷世事，便旋至竟年壽終盡不能得道，無可奈何。
「總猥憒擾皆貪愛欲，惑道者眾、悟之者寡，世間怱怱，無可聊賴。尊卑、上下、貧富、貴賤，勤苦怱務各懷殺毒，惡氣窈冥為妄興事，違逆天地不從人心，自然非惡先隨與之。恣聽所為待其罪極，其壽未盡便頓奪之。下入惡道，累世懟苦展轉其中，數千億劫無有出期。痛不可言，甚可哀愍。」
佛告彌勒菩薩、諸天人等：「我今語汝世間之事，人用是故，坐不得道。當熟思計遠離眾惡，擇其善者勤而行之。愛欲榮華不可常保，皆當別離無可樂者。曼佛在世當勤精進，其有]願生安樂國者，可得智慧明達、功德殊勝；勿得隨心所欲，虧負經戒在人後也。儻有疑意不解經者，可具問佛，當為說之。」
彌勒菩薩長跪白言：「佛威神尊重，所說快善，聽佛經者貫心思之。世人實爾如佛所言，今佛慈愍顯示大道，耳目開明長得度脫，聞佛所說莫不歡喜。諸天、人民、蠕動之類，皆蒙慈恩解脫憂苦。佛語教誡甚深甚善，智慧明見八方、上下、去來今事，莫不究暢。今我眾等所以蒙得度脫，皆佛前世求道之時謙苦所致。恩德普覆，福祿巍巍，光明徹照達空無極；開入泥洹，教授典攬威制消化，感動十方無窮無極。佛為法王尊超眾聖，普為一切天人之師，隨心所願皆令得道。今得值佛，復聞無量壽聲，靡不歡喜，心得開明。」
佛告彌勒：「汝言是也。若有慈敬於佛者，實為大善。天下久久乃復有佛，今我於此世作佛，演說經法，宣布道教，斷諸疑網；拔愛欲之本，杜眾惡之源。遊步三界無所拘閡，典攬智慧眾道之要，執持綱維昭然分明，開示五趣度未度者，決正生死泥洹之道。
「彌勒當知，汝從無數劫來修菩薩行，欲度眾生，其已久遠，從汝得道至于泥洹不可稱數。汝及十方諸天、人民一切四眾，永劫已來展轉五道，憂畏勤苦不可具言，乃至今世生死不絕，與佛相值聽受經法，又復得聞無量壽佛。快哉甚善，吾助爾喜。
「汝今亦可自厭生、死、老、病、痛苦、惡露、不淨、無可樂者，宜自決斷。端身正行，益作諸善；修己潔體，洗除心垢；言行忠信，表裏相應；人能自度，轉相拯濟；精明求願，積累善本。雖一世勤苦須臾之間，後生無量壽佛國快樂無極，長與道德合明，永拔生死根本，無復貪恚、愚癡、苦惱之患。欲壽一劫、百劫、千億萬劫，自在隨意皆可得之，無為自然次於泥洹之道。汝等宜各精進求心所願，無得疑惑中悔自為過咎，生彼邊地七寶宮殿，五百歲中受諸厄也。」
彌勒白佛：「受佛重誨，專精修學，如教奉行，不敢有疑。」
佛告彌勒：「汝等能於此世端心正意，不作眾惡，甚為至德，十方世界最無倫匹。所以者何？諸佛國土天人之類自然作善，不大為惡，易可開化。今我於此世間作佛，處於五惡、五痛、五燒之中，為最劇苦。教化群生令捨五惡、令去五痛、令離五燒；降化其意令持五善，獲其福德度世長壽泥洹之道。」
佛言：「何等為五惡？何等五痛？何等五燒？何等消化五惡、令持五善，獲其福德度世長壽泥洹之道？
其一惡者，諸天、人民、蠕動之類。欲為眾惡莫不皆然。強者伏弱轉相剋賊，殘害殺戮迭相吞噬，不知修善惡逆無道，後受殃罰自然趣向。神明記識犯者不赦，故有貧窮、下賤、乞匃、孤獨、聾盲、瘖啞、愚癡、憋惡，至有尫狂不逮之屬。又有尊貴、豪富、高才、明達皆由宿世慈孝、修善積德所致。世有常道、王法、牢獄不肯畏慎，為惡入罪受其殃罰，求望解脫難得免出。世間有此目前現事，壽終後世尤深尤劇，入其幽冥轉生受身。譬如王法痛苦極刑，故有自然三塗無量苦惱，轉貿其身、改形易道，所受壽命或長或短，魂神精識自然趣之。當獨值向相從共生，更相報復無有止已，殃惡未盡不得相離，展轉其中無有出期，難得解脫痛不可言。天地之間自然有是，雖不即時卒暴應至，善惡之道會當歸之。是為一大惡、一痛、一燒，勤苦如是。
「譬如大火焚燒人身，人能於中一心制意、端身正行，獨作諸善、不為眾惡者，身獨度脫，獲其福德度世上天泥洹之道，是為一大善也。」
佛言：「其二惡者，世間人民——父子、兄弟、室家、夫婦——都無義理，不順法度。奢婬憍縱，各欲快意，任心自恣，更相欺惑。心口各異、言念無實、佞諂不忠、巧言諛媚、嫉賢謗善，陷入怨枉。主上不明任用臣下、臣下自在機偽多端，踐度能行知其形勢。在位不正為其所欺，妄損忠良不當天心。臣欺其君、子欺其父，兄弟、夫婦、中外知識更相欺誑，各懷貪欲、瞋恚、愚癡，欲自厚己、欲貪多有，尊卑、上下心俱同然。破家亡身不顧前後，親屬內外坐之滅族。或時室家、知識、鄉黨、市里、愚民、野人轉共從事，更相剝害，忿成怨結。富有慳惜不肯施與，愛保貪重心勞身苦，如是至竟無所恃怙，獨來獨去無一隨者。善惡、禍福追命所生，或在樂處、或入苦毒，然後乃悔，當復何及？世間人民心愚少智，見善憎謗不思慕及，但欲為惡妄作非法，常懷盜心悕望他利，消散磨盡而復求索。邪心不正，懼人有色，不豫思計，事至乃悔。今世現有王法牢獄，隨罪趣向受其殃罰。因其前世不信道德、不修善本，今復為惡，天神剋識別其名籍，壽終神逝下入惡道，故有自然三塗無量苦惱。展轉其中，世世累劫無有出期，難得解脫痛不可言，是為二大惡、二痛、二燒，勤苦如是。
「譬如大火焚燒人身，人能於中一心制意、端身正行，獨作諸善、不為眾惡者，身獨度脫，獲其福德度世上天泥洹之道，是為二大善也。」
佛言：「其三惡者，世間人民相因寄生，共居天地之間，處年壽命無能幾何。上有賢明長者、尊貴豪富，下有貧窮㒋賤、尫劣愚夫，中有不善之人常懷邪惡，但念婬妷，煩滿胸中，愛欲交亂坐起不安，貪意守惜但欲唐得。眄睞細色邪態外逸，自妻厭憎私妄出入，費損家財事為非法，交結聚會興師相伐，攻劫殺戮強奪不道。惡心在外不自修業，盜竊趣得欲擊成事，恐勢迫脅歸給妻子，恣心快意極身作樂。或於親屬不避尊卑，家室中外患而苦之，亦復不畏王法禁令。如是之惡著於人鬼，日月照見、神明記識，故有自然三塗無量苦惱。展轉其中，世世累劫無有出期，難得解脫痛不可言，是為三大惡、三痛、三燒，勤苦如是。
「譬如大火焚燒人身，人能於中一心制意、端身正行，獨作諸善、不為眾惡者，身獨度脫，獲其福德度世上天泥洹之道，是為三大善也。」
佛言：「其四惡者，世間人民不念修善，轉相教令共為眾惡。兩舌、惡口、妄言、綺語、讒賊、鬪亂，憎嫉善人、敗壞賢明，於傍快喜。不孝二親、輕慢師長，朋友無信，難得誠實。尊貴自大謂己有道，橫行威勢侵易於人，不能自知，為惡無恥，自以強健欲人敬難，不畏天地、神明、日月，不肯作善，難可降化。自用偃蹇謂可常爾，無所憂懼，常懷憍慢。如是眾惡，天神記識，賴其前世頗作福德，小善扶接營護助之；今世為惡福德盡滅，諸善神鬼各去離之，身獨空立無所復依。壽命終盡諸惡所歸，自然迫促共趣奪之。又其名籍記在神明，殃咎牽引當往趣向，罪報自然無從捨離。但得前行入於火鑊，身心摧碎、精神痛苦，當斯之時悔復何及？天道自然，不得蹉跌，故有自然三塗無量苦惱。展轉其中，世世累劫無有出期，難得解脫痛不可言，是為四大惡、四痛、四燒，勤苦如是。
「譬如大火焚燒人身，人能於中一心制意、端身正行，獨作諸善、不為眾惡，身獨度脫，獲其福德度世上天泥洹之道，是為四大善也。」
佛言：「其五惡者，世間人民徙倚懈惰，不肯作善、治身修業，家室眷屬飢寒困苦。父母教誨瞋目怒應，言令不和違戾反逆譬如怨家，不如無子。取與無節，眾共患厭，負恩違義，無有報償之心。貧窮困乏不能復得，辜較縱奪放恣遊散，串數唐得用自賑給。耽酒嗜美、飲食無度，肆心蕩逸、魯扈抵突，不識人情強欲抑制。見人有善憎嫉惡之，無義、無禮，無所顧錄。自用職當不可諫曉，六親眷屬所資有無不能憂念。不惟父母之恩、不存師友之義，心常念惡、口常言惡、身常行惡，曾無一善。不信先聖諸佛經法、不信行道可得度世、不信死後神明更生、不信作善得善為惡得惡。欲殺真人，鬪亂眾僧，欲害父母、兄弟、眷屬，六親憎惡願令其死。
「如是世人心意俱然，愚癡曚昧而自以智慧，不知生所從來、死所趣向。不仁、不順，逆惡天地，而於其中悕望僥倖，欲求長生，會當歸死。慈心教誨令其念善，開示生死善惡之趣自然有是，而不信之；苦心與語無益其人，心中閉塞意不開解。大命將終悔懼交至，不豫修善臨窮方悔，悔之於後將何及乎？天地之間五道分明，恢廓窈冥浩浩茫茫，善惡報應禍福相承，身自當之無誰代者。
「數之自然應其所行，殃咎追命無得縱捨。善人行善，從樂入樂、從明入明；惡人行惡，從苦入苦、從冥入冥。誰能知者？獨佛知耳。教語開示，信用者少，生死不休，惡道不絕。如是，世人難可具盡，故有自然三塗無量苦惱。展轉其中，世世累劫無有出期，難得解脫，痛不可言，是為五大惡、五痛、五燒，勤苦如是。
「譬如大火焚燒人身，人能於中一心制意、端身正念，言行相副、所作至誠，所語如語、心口不轉，獨作諸善、不為眾惡者，身獨度脫，獲其福德度世上天泥洹之道，是為五大善也。」
佛告彌勒：「吾語汝等，是世五惡勤苦若此，五痛、五燒展轉相生，但作眾惡不修善本，皆悉自然入諸惡趣。或其今世先被殃病，求死不得、求生不得，罪惡所招示眾見之。身死隨行入三惡道，苦毒無量自相燋然。至其久後共作怨結，從小微起遂成大惡，皆由貪著財色、不能施慧，癡欲所迫、隨心思想，煩惱結縛無有解已，厚己諍利無所省錄。富貴榮華當時快意，不能忍辱不務修善，威勢無幾隨以磨滅，身生勞苦久後大劇。天道施張自然糺舉，綱[14]紀羅網上下相應，焭焭忪忪當入其中。古今有是，痛哉可傷！」
佛語彌勒：「世間如是，佛皆哀之。以威神力摧滅眾惡，悉令就善棄捐所思，奉持經戒、受行道法，無所違失，終得度世泥洹之道。」
佛言：「汝今諸天人民及後世人，得佛經語當熟思之，能於其中端心正行，主上為善、率化其下，轉相勅令各自端守，尊聖敬善、仁慈博愛。佛語教誨無敢虧負，當求度世拔斷生死眾惡之本，永離三塗無量憂畏苦痛之道。汝等於是廣殖德本，布恩施慧，勿犯道禁，忍辱、精進、一心、智慧轉相教化。
「為德立善，正心正意，齋戒清淨一日一夜，勝在無量壽國為善百歲。所以者何？彼佛國土無為自然，皆積眾善，無毛髮之惡，於此修善十日十夜，勝於他方諸佛國中為善千歲。所以者何？他方佛國為善者多、為惡者少，福德自然，無造惡之地。唯此間多惡無有自然，勤苦求欲轉相欺殆，心勞形困飲苦食毒，如是怱務未甞寧息。吾哀汝等天人之類，苦心誨喻教令修善，隨器開導授與經法，莫不承用，在意所願皆令得道。佛所遊履，國邑丘聚靡不蒙化，天下和順，日月清明，風雨以時，災厲不起，國豐民安，兵戈無用，崇德興仁，務修禮讓。」
佛言：「我哀愍汝等諸天人民，甚於父母念子。今吾於此世作佛，降化五惡、消除五痛、絕滅五燒，以善攻惡，拔生死之苦，令獲五德，昇無為之安。吾去世後經道漸滅，人民諂偽復為眾惡，五燒、五痛還如前法，久後轉劇不可悉說，我但為汝略言之耳。」
佛告彌勒：「汝等各善思之，轉相教誡，如佛經法，無得犯也。」
於是，彌勒菩薩合掌白言：「佛所說甚善。世人實爾，如來普慈哀愍悉令度脫，受佛重誨不敢違失。」
佛告阿難：「汝起更整衣服，合掌恭敬，禮無量壽佛。十方國土諸佛如來，常共稱揚讚歎彼佛，無著無閡。」
於是，阿難起整衣服，正身西向，恭敬合掌，五體投地禮無量壽佛。白言：「世尊！願見彼佛安樂國土及諸菩薩聲聞大眾。」
說是語已，即時無量壽佛放大光明，普照一切諸佛世界，金剛圍山、須彌山王、大小諸山，一切所有皆同一色。譬如劫水彌滿世界，其中萬物沈沒不現，滉瀁浩汗唯見大水；彼佛光明亦復如是，聲聞、菩薩一切光明皆悉隱蔽，唯見佛光明耀顯赫。
爾時，阿難即見無量壽佛，威德巍巍如須彌山王，高出一切諸世界上，相好光明靡不照耀。此會四眾一時悉見，彼見此土亦復如是。
爾時，佛告阿難及慈氏菩薩：「汝見彼國，從地已上至淨居天，其中所有微妙嚴淨自然之物，為悉見不？」
阿難對曰：「唯然，已見。」
「汝寧復聞無量壽佛大音宣布一切世界化眾生不？」
阿難對曰：「唯然，已聞。」
「彼國人民乘百千由旬七寶宮殿無所障閡，遍至十方供養諸佛，汝復見不？」
對曰：「已見。」
「彼國人民有胎生者，汝復見不？」
對曰：「已見。」
「其胎生者所處宮殿，或百由旬或五百由旬，各於其中受諸快樂，如忉利
爾時，慈氏菩薩白佛言：「世尊！何因何緣彼國人民胎生化生？」
佛告慈氏：「若有眾生以疑惑心修諸功德，願生彼國，不了佛智、不思議智、不可稱智、大乘廣智、無等無倫最上勝智，於此諸智疑惑不信；然猶信罪福，修習善本，願生其國。此諸眾生生彼宮殿，壽五百歲，常不見佛、不聞經法、不見菩薩聲聞聖眾，是故於彼國土謂之胎生。若有眾生明信佛智乃至勝智，作諸功德信心迴向，此諸眾生於七寶華中自然化生，加趺而坐，須臾之頃，身相光明，智慧功德如諸菩薩具足成就。
「復次，慈氏！他方諸大菩薩發心欲見無量壽佛，恭敬供養及諸菩薩聲聞之眾。彼菩薩等命終得生無量壽國，於七寶華中自然化生。彌勒當知，彼化生者智慧勝故。其胎生者皆無智慧，於五百歲中常不見佛、不聞經法、不見菩薩諸聲聞眾，無由供養於佛、不知菩薩法式、不得修習功德，當知此人宿世之時無有智慧，疑惑所致。」
佛告彌勒：「譬如轉輪聖王別有宮室，七寶莊飾，張設床帳，懸諸繒幡。若有諸小王子得罪於王，輒內彼宮中，繫以金鎖，供給飲食、衣服、床蓐、華香、伎樂，如轉輪王無所乏少。於意云何？此諸王子寧樂彼處不？」
對曰：「不也，但種種方便求諸大力欲自勉出。」
佛告彌勒：「此諸眾生亦復如是。以疑惑佛智生彼宮殿，無有形罰乃至一念惡事，但於五百歲中不見三寶，不得供養修諸善本。以此為苦，雖有餘樂猶不樂彼處。若此眾生識其本罪，深自悔責求離彼處，即得如意，往詣無量壽佛所恭敬供養，亦得遍至無量無數諸如來所修諸功德。彌勒當知，其有菩薩生疑惑者，為失大利。是故，應當明信諸佛無上智慧。」
彌勒菩薩白佛言：「世尊！於此世界有幾所不退菩薩生彼佛國？」
佛告彌勒：「於此世界有六十七億不退菩薩往生彼國。一一菩薩已曾供養無數諸佛，次如彌勒者也；諸小行菩薩及修習少功德者不可稱計，皆當往生。」
佛告彌勒：「不但我剎諸菩薩等往生彼國，他方佛土亦復如是。其第一佛名曰遠照，彼有百八十億菩薩皆當往生。其第二佛名曰寶藏，彼有九十億菩薩皆當往生。其第三佛名曰無量音，彼有二百二十億菩薩皆當往生。其第四佛名曰甘露味，彼有二百五十億菩薩皆當往生。其第五佛名曰龍勝，彼有十四億菩薩皆當往生。其第六佛名曰勝力，彼有萬四千菩薩皆當往生。其第七佛名曰師子，彼有五百億菩薩皆當往生。其第八佛名曰離垢光，彼有八十億菩薩皆當往生。其第九佛名曰德首，彼有六十億菩薩皆當往生。其第十佛名曰妙德山，彼有六十億菩薩皆當往生。其第十一佛名曰人王，彼有十億菩薩皆當往生。其第十二佛名曰無上華，彼有無數不可稱計諸菩薩眾——皆不退轉，智慧勇猛，已曾供養無量諸佛，於七日中即能攝取百千億劫大士所修堅固之法——斯等菩薩皆當往生。其第十三佛名曰無畏，彼有七百九十億大菩薩眾、諸小菩薩及比丘等不可稱計皆當往生。」
佛語彌勒：「不但此十四佛國中諸菩薩等當往生也，十方世界無量佛國其往生者亦復如是，甚多無數。我但說十方諸佛名號及菩薩、比丘生彼國者，晝夜一劫尚未能竟，我今為汝略說之耳。」
佛語彌勒：「其有得聞彼佛名號，歡喜踊躍，乃至一念，當知此人為得大利，則是具足無上功德。是故，彌勒！設有大火充滿三千大千世界，要當過此。聞是經法，歡喜信樂，受持讀誦，如說修行。所以者何？多有菩薩欲聞此經而不能得。若有眾生聞此經者，於無上道終不退轉，是故應當專心信受持誦說行。吾今為諸眾生說此經法，令見無量壽佛及其國土一切所有，所當為者皆可求之，無得以我滅度之後復生疑惑。當來之世經道滅盡，我以慈悲哀愍特留此經止住百歲，其有眾生值斯經者，隨意所願皆可得度。」
佛語彌勒：「如來興世難值難見、諸佛經道難得難聞；菩薩勝法諸波羅蜜得聞亦難；遇善知識、聞法能行此亦為難；若聞斯經信樂受持，難中之難無過此難。是故我法，如是作、如是說、如是教，應當信順，如法修行。」
爾時，世尊說此經法，無量眾生皆發無上正覺之心，萬二千那由他人得清淨法眼，二十二億諸天人民得阿那含，八十萬比丘漏盡意解，四十億菩薩得不退轉，以弘誓功德而自莊嚴，於將來世當成正覺。爾時，三千大千世界六種震動，大光普照十方國土，百千音樂自然而作，無量妙華芬芬而降。
佛說經已，彌勒菩薩及十方來諸菩薩眾，長老阿難、諸大聲聞，一切大眾，聞佛所說靡不歡喜。', '已發布'),
  (15, '佛說觀無量壽佛經', '宋西域三藏畺良耶舍譯', '如是我聞：一時，佛在王舍城耆闍崛山中，與大比丘眾千二百五十人俱；菩薩三萬二千，文殊師利法王子而為上首。爾時王舍大城有一太子，名阿闍世，隨順調達惡友之教，收執父王頻婆娑羅，幽閉置於七重室內，制諸群臣，一不得往。國大夫人，名韋提希，恭敬大王，澡浴清淨，以酥蜜和，用塗其身，諸瓔珞中盛葡萄漿，密以上王。爾時大王，食麨飲漿，求水漱口；漱口畢已，合掌恭敬，向耆闍崛山，遙禮世尊，而作是言：「大目乾連是吾親友，願興慈悲，授我八戒。」時目乾連如鷹隼飛，疾至王所；日日如是，授王八戒。世尊亦遣尊者富樓那，為王說法。如是時間經三七日，王食麨蜜得聞法故，顏色和悅。
時阿闍世問守門人：「父王今者猶存在耶？」時守門者白言：「大王！國大夫人身塗蜜，瓔珞盛漿，持用上王；沙門目連及富樓那，從空而來，為王說法，不可禁制。」時阿闍世聞此語已，怒其母曰：「我母是賊，與賊為伴；沙門惡人，幻惑呪術，令此惡王多日不死。」即執利劍欲害其母。
時有一臣，名曰月光，聰明多智，及與耆婆，為王作禮。白言：「大王！臣聞毘陀論經說：『劫初已來，有諸惡王貪國位故，殺害其父一萬八千。』未曾聞有無道害母。王今為此殺逆之事，污剎利種，臣不忍聞！是栴陀羅，我等不宜復住於此。」時二大臣說此語竟，以手按劍，却行而退。時阿闍世驚怖惶懼，告耆婆言：「汝不為我耶？」耆婆白言：「大王！慎莫害母。」王聞此語，懺悔求救，即便捨劍，止不害母，勅語內官：「閉置深宮，不令復出。」
時韋提希被幽閉已，愁憂憔悴；遙向耆闍崛山，為佛作禮，而作是言：「如來世尊在昔之時，恒遣阿難來慰問我；我今愁憂，世尊威重，無由得見；願遣目連、尊者阿難，與我相見。」作是語已，悲泣雨淚，遙向佛禮。未舉頭頃，爾時世尊在耆闍崛山，知韋提希心之所念，即勅大目揵連及以阿難，從空而來。佛從耆闍崛山沒，於王宮出。
時韋提希禮已舉頭，見世尊釋迦牟尼佛，身紫金色坐百寶蓮華。目連侍左，阿難在右，釋梵護世諸天在虛空中，普雨天華，持用供養。時韋提希見佛世尊，自絕瓔珞，舉身投地，號泣向佛。白言：「世尊！我宿何罪，生此惡子？世尊復有何等因緣，與提婆達多共為眷屬？唯願世尊，為我廣說無憂惱處，我當往生，不樂閻浮提濁惡世也。此濁惡處，地獄、餓鬼、畜生盈滿，多不善聚。願我未來不聞惡聲，不見惡人。今向世尊五體投地，求哀懺悔。唯願佛日教我觀於清淨業處。」
爾時世尊放眉間光，其光金色，遍照十方無量世界；還住佛頂，化為金臺，如須彌山。十方諸佛淨妙國土，皆於中現。或有國土七寶合成；復有國土純是蓮花；復有國土如自在天宮；復有國土如頗梨鏡；十方國土皆於中現。有如是等無量諸佛國土嚴顯可觀，令韋提希見。
時韋提希白佛言：「世尊！是諸佛土，雖復清淨，皆有光明；我今樂生極樂世界阿彌陀佛所。唯願世尊，教我思惟，教我正受。」
爾時世尊即便微笑，有五色光，從佛口出，一一光照頻婆娑羅王頂。爾時大王雖在幽閉，心眼無障，遙見世尊，頭面作禮；自然增進，成阿那含。
爾時世尊告韋提希：「汝今知不？阿彌陀佛去此不遠；汝當繫念，諦觀彼國淨業成者。我今為汝廣說眾譬，亦令未來世一切凡夫欲修淨業者，得生西方極樂國土。欲生彼國者，當修三福：一者、孝養父母，奉事師長，慈心不殺，修十善業。二者、受持三歸，具足眾戒，不犯威儀。三者、發菩提心，深信因果，讀誦大乘，勸進行者。如此三事名為淨業。」
佛告韋提希：「汝今知不？此三種業，乃是過去、未來、現在三世諸佛淨業正因。」
佛告阿難及韋提希：「諦聽，諦聽！善思念之。如來今者，為未來世一切眾生為煩惱賊之所害者，說清淨業。善哉韋提希！快問此事。阿難！汝當受持，廣為多眾宣說佛語。如來今者，教韋提希及未來世一切眾生觀於西方極樂世界。以佛力故，當得見彼清淨國土，如執明鏡自見面像。見彼國土極妙樂事，心歡喜故，應時即得無生法忍。」
佛告韋提希：「汝是凡夫，心想羸劣，未得天眼，不能遠觀；諸佛如來有異方便，令汝得見。」
時韋提希白佛言：「世尊！如我今者，以佛力故見彼國土。若佛滅後，諸眾生等，濁惡不善，五苦所逼，云何當見阿彌陀佛極樂世界？」
佛告韋提希：「汝及眾生應當專心，繫念一處，想於西方。云何作想？凡作想者，一切眾生自非生盲，有目之徒，皆見日沒。當起想念，正坐西向，諦觀於日，令心堅住，專想不移。見日欲沒，狀如懸鼓。既見日已，閉目開目皆令明了。是為日想，名曰初觀。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「初觀成已，次作水想。想見西方一切皆是大水，見水澄清，亦令明了，無分散意。既見水已，當起氷想。見氷映徹，作琉璃想。此想成已，見琉璃地，內外映徹。下有金剛七寶金幢，擎琉璃地。其幢八方，八楞具足，一一方面，百寶所成，一一寶珠，有千光明，一光明，八萬四千色，映琉璃地，如億千日，不可具見。琉璃地上，以黃金繩，雜廁間錯，以七寶界，分齊分明，一一寶中，有五百色光。其光如花，又似星月，懸處虛空，成光明臺。樓閣千萬，百寶合成，於臺兩邊，各有百億花幢，無量樂器，以為莊嚴。八種清風從光明出，鼓此樂器，演說苦、空、無常、無我之音，是為水想，名第二觀。此想成時，一一觀之，極令了了。閉目開目，不令散失，唯除食時，恒憶此事。作此觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「水想成已，名為粗見極樂國地。若得三昧，見彼國地，了了分明，不可具說。是為地想，名第三觀。」
佛告阿難：「汝持佛語，為未來世一切大眾欲脫苦者，說是觀地法。若觀是地者，除八十億劫生死之罪。捨身他世，必生淨國，心得無疑。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「地想成已，次觀寶樹。觀寶樹者，一一觀之，作七重行樹想。一一樹高八千由旬，其諸寶樹，七寶花葉無不具足。一一華葉，作異寶色。琉璃色中出金色光；頗梨色中出紅色光；馬腦色中出車𤦲光；車𤦲色中出綠真珠光；珊瑚琥珀一切眾寶以為映飾。妙真珠網彌覆樹上，一一樹上有七重網，一一網間有五百億妙華宮殿，如梵王宮。諸天童子自然在中，一一童子有五百億釋迦毘楞伽摩尼寶以為瓔珞；其摩尼光照百由旬，猶如和合百億日月，不可具名，眾寶間錯色中上者。此諸寶樹，行行相當，葉葉相次，於眾葉間生諸妙花，花上自然有七寶果。一一樹葉，縱廣正等二十五由旬；其葉千色有百種畫，如天纓珞；有眾妙華，作閻浮檀金色；如旋火輪，宛轉葉間，踊生諸果，如帝釋瓶；有大光明，化成幢幡無量寶蓋。是寶蓋中，映現三千大千世界一切佛事；十方佛國亦於中現。見此樹已，亦當次第一一觀之，觀見樹莖、枝葉、華果，皆令分明。是為樹想，名第四觀。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「樹想成已，次當想水。欲想水者，極樂國土有八池水。一一池水七寶所成；其寶柔軟從如意珠王生，分為十四支；一一支作七寶色。黃金為渠，渠下皆以雜色金剛以為底沙。一一水中有六十億七寶蓮花，一一蓮華團圓正等十二由旬。其摩尼水流注華間，尋樹上下。其聲微妙，演說苦、空、無常、無我、諸波羅蜜，復有讚歎諸佛相好者。從如意珠王踊出金色微妙光明，其光化為百寶色鳥，和鳴哀雅，常讚念佛、念法、念僧，是為八功德水想，名第五觀。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「眾寶國土，一一界上有五百億寶樓，其樓閣中有無量諸天，作天伎樂。又有樂器懸處虛空，如天寶幢不鼓自鳴。此眾音中，皆說念佛、念法、念比丘僧。此想成已，名為粗見極樂世界寶樹、寶地、寶池，是為總觀想，名第六觀。若見此者，除無量億劫極重惡業，命終之後必生彼國。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「諦聽，諦聽！善思念之。吾當為汝分別解說除苦惱法，汝等憶持，廣為大眾分別解說。」說是語時，無量壽佛住立空中，觀世音、大勢至，是二大士侍立左右。光明熾盛不可具見，百千閻浮檀金色不得為比。
時韋提希見無量壽佛已，接足作禮，白佛言：「世尊！我今因佛力故，得見無量壽佛及二菩薩，未來眾生，當云何觀無量壽佛及二菩薩？」
佛告韋提希：「欲觀彼佛者，當起想念，於七寶地上作蓮花想，令其蓮花一一葉作百寶色。有八萬四千脈，猶如天畫；一一脈有八萬四千光，了了分明，皆令得見。華葉小者，縱廣二百五十由旬；如是蓮華有八萬四千大葉，一一葉間，有百億摩尼珠王以為映飾。一一摩尼珠放千光明，其光如蓋，七寶合成，遍覆地上。釋迦毘楞伽摩尼寶以為其臺；此蓮花臺，八萬金剛甄叔迦寶，梵摩尼寶，妙真珠網，以為交飾。於其臺上，自然而有四柱寶幢，一一寶幢如百千萬億須彌山；幢上寶縵如夜摩天宮，復有五百億微妙寶珠，以為映飾。一一寶珠有八萬四千光，一一光作八萬四千異種金色，一一金色遍其寶土，處處變化，各作異相；或為金剛臺，或作真珠網，或作雜花雲，於十方面隨意變現，施作佛事，是為花座想，名第七觀。」
佛告阿難：「如此妙花，是本法藏比丘願力所成，若欲念彼佛者，當先作此妙花座想。作此想時不得雜觀；皆應一一觀之，一一葉，一一珠，一一光，一一臺，一一幢，皆令分明，如於鏡中自見面像。此想成者，滅除五百億劫生死之罪，必定當生極樂世界。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「見此事已，次當想佛。所以者何？諸佛如來是法界身，遍入一切眾生心想中；是故汝等心想佛時，是心即是三十二相、八十隨形好。是心作佛，是心是佛。諸佛正遍知海，從心想生，是故應當一心繫念，諦觀彼佛、多陀阿伽度、阿羅呵、三藐三佛陀。想彼佛者，先當想像。閉目開目，見一寶像，如閻浮檀金色，坐彼華上。像既坐已，心眼得開，了了分明，見極樂國七寶莊嚴，寶地、寶池、寶樹行列，諸天寶縵彌覆樹上，眾寶羅網滿虛空中。見如此事，極令明了，如觀掌中。見此事已，復當更作一大蓮華在佛左邊，如前蓮華等無有異。復作一大蓮華在佛右邊，想一觀世音菩薩像坐左華座，亦放金光如前無異。想一大勢至菩薩像坐右華座。此想成時，佛菩薩像皆放妙光；其光金色，照諸寶樹。一一樹下亦有三蓮華，諸蓮華上各有一佛二菩薩像，遍滿彼國。此想成時，行者當聞水流、光明及諸寶樹、鳧鴈、鴛鴦皆說妙法。出定、入定恒聞妙法。行者所聞，出定之時憶持不捨，令與修多羅合。若不合者，名為妄想，若與合者，名為麁想見極樂世界。是為想像，名第八觀。作是觀者，除無量億劫生死之罪，於現身中得念佛三昧。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「此想成已，次當更觀無量壽佛身相光明。阿難當知！無量壽佛身，如百千萬億夜摩天閻浮檀金色。佛身高六十萬億那由他恒河沙由旬；眉間白毫右旋宛轉，如五須彌山。佛眼清淨如四大海水，清白分明。身諸毛孔演出光明，如須彌山。彼佛圓光如百億三千大千世界；於圓光中，有百萬億那由他恒河沙化佛；一一化佛，亦有眾多無數化菩薩，以為侍者。無量壽佛有八萬四千相；一一相中，各有八萬四千隨形好；一一好中復有八萬四千光明；一一光明遍照十方世界，念佛眾生攝取不捨。其光相好及與化佛，不可具說；但當憶想令心明見。見此事者，即見十方一切諸佛，以見諸佛故名念佛三昧。作是觀者，名觀一切佛身，以觀佛身故亦見佛心。諸佛心者大慈悲是，以無緣慈攝諸眾生。作此觀者，捨身他世，生諸佛前，得無生忍。是故智者應當繫心諦觀無量壽佛。觀無量壽佛者，從一相好入，但觀眉間白毫，極令明了。見眉間白毫相者，八萬四千相好自然當見。見無量壽佛者，即見十方無量諸佛；得見無量諸佛故，諸佛現前受記。是為遍觀一切色想，名第九觀。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「見無量壽佛了了分明已，次亦應觀觀世音菩薩。此菩薩身長八十億那由他恒河沙由旬，身紫金色，頂有肉髻，項有圓光，面各百千由旬。其圓光中有五百化佛，如釋迦牟尼。一一化佛，有五百菩薩，無量諸天，以為侍者。舉身光中五道眾生，一切色相皆於中現。頂上毘楞伽摩尼妙寶，以為天冠。其天冠中有一立化佛，高二十五由旬。觀世音菩薩面如閻浮檀金色；眉間毫相備七寶色，流出八萬四千種光明；一一光明，有無量無數百千化佛；一一化佛，無數化菩薩以為侍者，變現自在滿十方界。臂如紅蓮花色，有八十億微妙光明，以為瓔珞；其瓔珞中，普現一切諸莊嚴事。手掌作五百億雜蓮華色；手十指端，一一指端有八萬四千畫，猶如印文。一一畫有八萬四千色；一一色有八萬四千光，其光柔軟普照一切，以此寶手接引眾生。舉足時，足下有千輻輪相，自然化成五百億光明臺。下足時，有金剛摩尼花，布散一切莫不彌滿。其餘身相，眾好具足，如佛無異，唯頂上肉髻及無見頂相，不及世尊。是為觀觀世音菩薩真實色身想，名第十觀。」
佛告阿難：「若欲觀觀世音菩薩當作是觀。作是觀者不遇諸禍，淨除業障，除無數劫生死之罪。如此菩薩，但聞其名，獲無量福，何況諦觀！若有欲觀觀世音菩薩者，當先觀頂上肉髻，次觀天冠。其餘眾相亦次第觀之，悉令明了，如觀掌中。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「次觀大勢至菩薩。此菩薩身量大小亦如觀世音，圓光面各二百二十五由旬，照二百五十由旬。舉身光明照十方國，作紫金色。有緣眾生皆悉得見。但見此菩薩一毛孔光，即見十方無量諸佛淨妙光明，是故號此菩薩名無邊光。以智慧光普照一切，令離三塗，得無上力，是故號此菩薩名大勢至。此菩薩天冠有五百寶蓮華；一一寶華有五百寶臺。一一臺中，十方諸佛淨妙國土廣長之相，皆於中現。頂上肉髻如鉢頭摩花。於肉髻上有一寶瓶，盛諸光明，普現佛事。餘諸身相如觀世音，等無有異。此菩薩行時，十方世界一切震動，當地動處各有五百億寶花。一一寶花莊嚴高顯，如極樂世界。此菩薩坐時，七寶國土一時動搖。從下方金光佛剎，乃至上方光明王佛剎，於其中間無量塵數分身無量壽佛，分身觀世音、大勢至，皆悉雲集極樂國土，側塞空中坐蓮華座，演說妙法，度苦眾生。作此觀者，名為觀見大勢至菩薩；是為觀大勢至色身相。觀此菩薩者名第十一觀，除無數劫阿僧祇生死之罪；作是觀者不處胞胎，常遊諸佛淨妙國土。此觀成已，名為具足觀觀世音及大勢至。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「見此事時當起想作心，自見生於西方極樂世界，於蓮華中結跏趺坐，作蓮華合想，作蓮華開想。蓮華開時，有五百色光來照身想；眼目開想，見佛菩薩滿虛空中，水鳥、樹林及與諸佛，所出音聲，皆演妙法，與十二部經合。若出定時憶持不失。見此事已，名見無量壽佛極樂世界。是為普觀想，名第十二觀。無量壽佛化身無數，與觀世音及大勢至，常來至此行人之所。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「若欲至心生西方者，先當觀於一丈六像在池水上。如先所說，無量壽佛身量無邊，非是凡夫心力所及。然彼如來宿願力故，有憶想者必得成就。但想佛像得無量福，況復觀佛具足身相！阿彌陀佛神通如意，於十方國變現自在。或現大身滿虛空中；或現小身丈六八尺。所現之形皆真金色，圓光化佛及寶蓮花，如上所說。觀世音菩薩及大勢至，於一切處身同眾生，但觀首相，知是觀世音，知是大勢至，此二菩薩助阿彌陀佛，普化一切。是為雜想觀，名第十三觀。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「凡生西方有九品人。上品上生者，若有眾生願生彼國者，發三種心，即便往生。何等為三？一者、至誠心。二者、深心。三者、迴向發願心。具三心者必生彼國。復有三種眾生，當得往生。何等為三？一者、慈心不殺，具諸戒行。二者、讀誦大乘方等經典。三者、修行六念，迴向發願生彼佛國。具此功德，一日乃至七日，即得往生。生彼國時，此人精進勇猛故，阿彌陀如來與觀世音及大勢至，無數化佛，百千比丘，聲聞大眾，無量諸天，七寶宮殿，觀世音菩薩執金剛臺，與大勢至菩薩至行者前。阿彌陀佛放大光明，照行者身，與諸菩薩授手迎接。觀世音、大勢至與無數菩薩，讚歎行者，勸進其心。行者見已，歡喜踊躍。自見其身乘金剛臺，隨從佛後，如彈指頃，往生彼國。生彼國已，見佛色身眾相具足，見諸菩薩色相具足。光明寶林，演說妙法。聞已即悟無生法忍。經須臾間歷事諸佛，遍十方界，於諸佛前次第受記。還至本國，得無量百千陀羅尼門，是名上品上生者。
「上品中生者，不必受持讀誦方等經典。善解義趣，於第一義心不驚動，深信因果，不謗大乘；以此功德，迴向願求生極樂國。行此行者命欲終時，阿彌陀佛與觀世音及大勢至，無量大眾，眷屬圍繞，持紫金臺至行者前，讚言：『法子！汝行大乘，解第一義，是故我今來迎接汝。』與千化佛一時授手。行者自見坐紫金臺，合掌叉手，讚歎諸佛，如一念頃，即生彼國七寶池中。此紫金臺如大寶花，經宿即開。行者身作紫磨金色，足下亦有七寶蓮華。佛及菩薩俱放光明，照行者身，目即開明。因前宿習，普聞眾聲，純說甚深第一義諦。即下金臺，禮佛合掌讚歎世尊。經於七日，應時即於阿耨多羅三藐三菩提，得不退轉。應時即能飛至十方，歷事諸佛，於諸佛所修諸三昧。經一小劫得無生法忍，現前受記，是名上品中生者。
「上品下生者，亦信因果，不謗大乘，但發無上道心，以此功德，迴向願求生極樂國。彼行者命欲終時，阿彌陀佛及觀世音并大勢至，與諸眷屬持金蓮華，化作五百化佛，來迎此人。五百化佛一時授手，讚言：『法子！汝今清淨，發無上道心，我來迎汝。』見此事時，即自見身坐金蓮花。坐已華合，隨世尊後，即得往生七寶池中。一日一夜蓮花乃開，七日之中乃得見佛。雖見佛身，於眾相好心不明了，於三七日後乃了了見。聞眾音聲，皆演妙法。遊歷十方，供養諸佛。於諸佛前聞甚深法，經三小劫得百法明門，住歡喜地。是名上品下生者。是名上輩生想，名第十四觀。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「中品上生者，若有眾生受持五戒，持八戒齋，修行諸戒，不造五逆，無眾過惡；以此善根，迴向願求生於西方極樂世界。行者臨命終時，阿彌陀佛與諸比丘，眷屬圍繞，放金色光至其人所，演說苦、空、無常、無我，讚歎出家得離眾苦。行者見已，心大歡喜。自見己身坐蓮花臺，長跪合掌為佛作禮。未舉頭頃即得往生極樂世界，蓮花尋開。當華敷時，聞眾音聲讚歎四諦，應時即得阿羅漢道，三明、六通、具八解脫；是名中品上生者。
「中品中生者，若有眾生，若一日一夜持八戒齋，若一日一夜持沙彌戒，若一日一夜持具足戒，威儀無缺。以此功德，迴向願求生極樂國。戒香薰修，如此行者命欲終時，見阿彌陀佛與諸眷屬放金色光，持七寶蓮花至行者前，行者自聞空中有聲，讚言：『善男子！如汝善人，隨順三世諸佛教故，我來迎汝。』行者自見坐蓮花上，蓮花即合，生於西方極樂世界。在寶池中，經於七日蓮花乃敷。花既敷已，開目合掌，讚歎世尊。聞法歡喜，得須陀洹，經半劫已成阿羅漢；是名中品中生者。
「中品下生者，若有善男子、善女人，孝養父母，行世仁義，此人命欲終時，遇善知識為其廣說阿彌陀佛國土樂事，亦說法藏比丘四十八大願。聞此事已，尋即命終。譬如壯士屈伸臂頃，即生西方極樂世界。生經七日，遇觀世音及大勢至，聞法歡喜得須陀洹。過一小劫，成阿羅漢。是名中品下生者。是名中輩生想，名第十五觀。作是觀者，名為正觀。若他觀者，名為邪觀。」
佛告阿難及韋提希：「下品上生者，或有眾生作眾惡業，雖不誹謗方等經典，如此愚人，多造惡法，無有慚愧，命欲終時遇善知識，為讚大乘十二部經首題名字。以聞如是諸經名故，除却千劫極重惡業。智者復教合掌叉手，稱南無阿彌陀佛。稱佛名故，除五十億劫生死之罪。爾時彼佛，即遣化佛，化觀世音，化大勢至，至行者前，讚言：『善哉！善男子！汝稱佛名故諸罪消滅，我來迎汝。』作是語已，行者即見化佛光明，遍滿其室，見已歡喜，即便命終。乘寶蓮花，隨化佛後，生寶池中，經七七日蓮花乃敷。當花敷時，大悲觀世音菩薩，及大勢至菩薩，放大光明，住其人前，為說甚深十二部經。聞已信解，發無上道心。經十小劫，具百法明門，得入初地；是名下品上生者；得聞佛名、法名及聞僧名，聞三寶名即得往生。」
佛告阿難及韋提希：「下品中生者，或有眾生，毀犯五戒、八戒及具足戒，如此愚人，偷僧祇物，盜現前僧物，不淨說法，無有慚愧，以諸惡法而自莊嚴。如此罪人，以惡業故應墮地獄。命欲終時，地獄眾火一時俱至，遇善知識以大慈悲，即為讚說阿彌陀佛十力威德，廣讚彼佛光明神力，亦讚戒、定、慧、解脫、解脫知見。此人聞已，除八十億劫生死之罪。地獄猛火化為涼風，吹諸天華。華上皆有化佛菩薩，迎接此人。如一念頃，即得往生七寶池中蓮花之內，經於六劫，蓮花乃敷。當華敷時，觀世音、大勢至，以梵音聲安慰彼人，為說大乘甚深經典。聞此法已，應時即發無上道心。是名下品中生者。」
佛告阿難及韋提希：「下品下生者，或有眾生作不善業，五逆、十惡，具諸不善。如此愚人以惡業故，應墮惡道，經歷多劫，受苦無窮。如此愚人臨命終時，遇善知識，種種安慰，為說妙法，教令念佛，彼人苦逼不遑念佛。善友告言：『汝若不能念彼佛者，應稱歸命無量壽佛。』如是至心令聲不絕，具足十念，稱南無阿彌陀佛。稱佛名故，於念念中，除八十億劫生死之罪。命終之[時見金蓮花，猶如日輪，住其人前，如一念頃，即得往生極樂世界。於蓮花中滿十二大劫，蓮花方開。當花敷時，觀世音、大勢至以大悲音聲，即為其人廣說實相，除滅罪法。聞已歡喜，應時即發菩提之心；是名下品下生者。是名下輩生想，名第十六觀。」
爾時世尊說是語時，韋提希與五百侍女，聞佛所說，應時即見極樂世界廣長之相，得見佛身及二菩薩。心生歡喜，歎未曾有，豁然大悟，得無生忍。五百侍女發阿耨多羅三藐三菩提心，願生彼國。世尊悉記，皆當往生，生彼國已，獲得諸佛現前三昧。無量諸天，發無上道心。
爾時阿難，即從座起，前白佛言：「世尊！當何名此經？此法之要，當云何受持？」佛告阿難：「此經名『觀極樂國土無量壽佛觀世音菩薩大勢至菩薩』，亦名『淨除業障生諸佛前』。汝等受持，無令忘失！行此三昧者，現身得見無量壽佛及二大士。若善男子及善女人，但聞佛名、二菩薩名，除無量劫生死之罪，何況憶念！若念佛者，當知此人即是人中芬陀利花，觀世音菩薩、大勢至菩薩為其勝友，當坐道場，生諸佛家。」
佛告阿難：「汝好持是語。持是語者，即是持無量壽佛名。」
佛說此語時，尊者目連、尊者阿難及韋提希等，聞佛所說，皆大歡喜。
爾時世尊，足步虛空，還耆闍崛山。爾時，阿難廣為大眾說如上事。無量人、天、龍、神、夜叉，聞佛所說，皆大歡喜，禮佛而退。', '已發布'),
  (16, '大方廣佛華嚴經卷第四十', null, '入不思議解脫境界普賢行願品 
爾時，普賢菩薩摩訶薩稱歎如來勝功德已，告諸菩薩及善財言：「善男子！如來功德，假使十方一切諸佛，經不可說不可說佛剎極微塵數劫，相續演說，不可窮盡。若欲成就此功德門，應修十種廣大行願。何等為十？一者、禮敬諸佛，二者、稱讚如來，三者、廣修供養，四者、懺悔業障，五者、隨喜功德，六者、請轉法輪，七者、請佛住世，八者、常隨佛學，九者、恒順眾生，十者、普皆迴向。」
善財白言：「大聖！云何禮敬，乃至迴向？」
普賢菩薩告善財言：「善男子！言禮敬諸佛者：所有盡法界、虛空界十方三世一切佛剎極微塵數諸佛世尊，我以普賢行願力故，起深信解，如對目前，悉以清淨身、語、意業，常修禮敬；一一佛所，皆現不可說不可說佛剎極微塵數身，一一身遍禮不可說不可說佛剎極微塵數佛；虛空界盡，我禮乃盡，而虛空界不可盡故，我此禮敬，無有窮盡。如是乃至眾生界盡、眾生業盡、眾生煩惱盡，我禮乃盡。而眾生界乃至煩惱無有盡故，我此禮敬無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言稱讚如來者：所有盡法界、虛空界十方三世一切剎土所有極微一一塵中，皆有一切世界極微塵數佛，一一佛所皆有菩薩海會圍遶，我當悉以甚深勝解，現前知見；各以出過辯才天女微妙舌根，一一舌根出無盡音聲海，一一音聲出一切言辭海，稱揚讚歎一切如來諸功德海，窮未來際相續不斷，盡於法界無不周遍。如是虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我讚乃盡。而虛空界乃至煩惱無有盡故，我此讚歎無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言廣修供養者：所有盡法界、虛空界十方三世一切佛剎極微塵中，一一各有一切世界極微塵數佛，一一佛所種種菩薩海會圍遶，我以普賢行願力故，起深信解，現前知見，悉以上妙諸供養具而為供養。所謂：華雲、鬘雲、天音樂雲、天傘蓋雲、天衣服雲、天種種香、塗香、燒香、末香，如是等雲，一一量如須彌山王；然種種燈，酥燈、油燈、諸香油燈，一一燈炷如須彌山，一一燈油如大海水，以如是等諸供養具常為供養。善男子！諸供養中，法供養最。所謂：如說修行供養、利益眾生供養、攝受眾生供養、代眾生苦供養、勤修善根供養、不捨菩薩業供養、不離菩提心供養。善男子！如前供養無量功德，比法供養一念功德百分不及一，千分不及一，百千俱胝那由他分、迦羅分、算分、數分、諭分、優婆尼沙陀分亦不及一。何以故？以諸如來尊重法故，以如說修行出生諸佛故。若諸菩薩行法供養，則得成就供養如來，如是修行是真供養故。此廣大最勝供養虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我供乃盡。而虛空界乃至煩惱不可盡故，我此供養亦無有盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言懺除業障者：菩薩自念我於過去無始劫中，由貪、瞋、癡發身、口、意，作諸惡業無量無邊。若此惡業有體相者，盡虛空界不能容受。我今悉以清淨三業，遍於法界極微塵剎一切諸佛菩薩眾前，誠心懺悔，後不復造，恒住淨戒一切功德。如是虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我懺乃盡。而虛空界乃至眾生煩惱不可盡故，我此懺悔無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言隨喜功德者：所有盡法界、虛空界十方三世一切佛剎極微塵數諸佛如來，從初發心為一切智，勤修福聚，不惜身命，經不可說不可說佛剎極微塵數劫，一一劫中捨不可說不可說佛剎極微塵數頭、目、手、足，如是一切難行、苦行，圓滿種種波羅蜜門，證入種種菩薩智地，成就諸佛無上菩提及般涅槃，分布舍利，所有善根，我皆隨喜。及彼十方一切世界，六趣、四生一切種類所有功德，乃至一塵我皆隨喜。十方三世一切聲聞及辟支佛、有學、無學所有功德，我皆隨喜。一切菩薩所修無量難行、苦行，志求無上正等菩提廣大功德，我皆隨喜。如是虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我此隨喜無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言請轉法輪者：所有盡法界、虛空界十方三世一切佛剎極微塵中，一一各有不可說不可說佛剎極微塵數廣大佛剎，一一剎中念念有不可說不可說佛剎極微塵數一切諸佛成等正覺，一切菩薩海會圍遶，而我悉以身、口、意業種種方便，慇懃勸請轉妙法輪。如是虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我常勸請一切諸佛轉正法輪無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言請佛住世者：所有盡法界、虛空界十方三世一切佛剎極微塵數諸佛如來將欲示現般涅槃者，及諸菩薩、聲聞、緣覺、有學、無學，乃至一切諸善知識，我悉勸請莫入涅槃，經於一切佛剎極微塵數劫，為欲利樂一切眾生。如是虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我此勸請無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言常隨佛學者：如此娑婆世界毘盧遮那如來，從初發心精進不退，以不可說不可說身命而為布施；剝皮為紙，折骨為筆，刺血為墨，書寫經典，積如須彌，為重法故，不惜身命，何況王位、城邑、聚落、宮殿、園林一切所有，及餘種種難行、苦行，乃至樹下成大菩提，示種種神通，起種種變化，現種種佛身，處種種眾會：或處一切諸大菩薩眾會道場，或處聲聞及辟支佛眾會道場，或處轉輪聖王、小王眷屬眾會道場，或處剎利及婆羅門、長者、居士眾會道場，乃至或處天龍八部、人、非人等眾會道場。處於如是種種眾會，以圓滿音，如大雷震，隨其樂欲，成熟眾生，乃至示現入於涅槃。如是一切，我皆隨學，如今世尊毘盧遮那，如是盡法界、虛空界十方三世一切佛剎，所有塵中一切如來皆亦如是，於念念中，我皆隨學。如是虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我此隨學無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言恒順眾生者：謂盡法界、虛空界十方剎海，所有眾生種種差別，所謂：卵生、胎生、濕生、化生，或有依於地、水、火、風而生住者，或有依空及諸卉木而生住者，種種生類、種種色身、種種形狀、種種相貌、種種壽量、種種族類、種種名號、種種心性、種種知見、種種欲樂、種種意行、種種威儀、種種衣服、種種飲食，處於種種村營、聚落、城邑、宮殿，乃至一切天龍八部、人、非人等，無足、二足、四足、多足，有色、無色，有想、無想、非有想、非無想，如是等類，我皆於彼隨順而轉，種種承事，種種供養，如敬父母，如奉師長，及阿羅漢乃至如來，等無有異。於諸病苦為作良醫，於失道者示其正路，於闇夜中為作光明，於貧窮者令得伏藏，菩薩如是平等饒益一切眾生。何以故？菩薩若能隨順眾生，則為隨順供養諸佛；若於眾生尊重承事，則為尊重承事如來；若令眾生生歡喜者，則令一切如來歡喜。何以故？諸佛如來以大悲心而為體故。因於眾生而起大悲，因於大悲生菩提心，因菩提心成等正覺。譬如曠野沙磧之中有大樹王，若根得水，枝葉、華果悉皆繁茂。生死曠野菩提樹王，亦復如是。一切眾生而為樹根，諸佛菩薩而為華果，以大悲水饒益眾生，則能成就諸佛菩薩智慧華果。何以故？若諸菩薩以大悲水饒益眾生，則能成就阿耨多羅三藐三菩提故。是故菩提屬於眾生，若無眾生，一切菩薩終不能成無上正覺。善男子！汝於此義應如是解。以於眾生心平等故，則能成就圓滿大悲，以大悲心隨眾生故，則能成就供養如來。菩薩如是隨順眾生，虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我此隨順無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。
「復次，善男子！言普皆迴向者：從初禮拜乃至隨順，所有功德皆悉迴向盡法界、虛空界一切眾生，願令眾生常得安樂，無諸病苦；欲行惡法皆悉不成，所修善業皆速成就；關閉一切諸惡趣門，開示人天涅槃正路；若諸眾生因其積集諸惡業故，所感一切極重苦果我皆代受；令彼眾生悉得解脫究竟成就無上菩提。菩薩如是所修迴向，虛空界盡、眾生界盡、眾生業盡、眾生煩惱盡，我此迴向無有窮盡，念念相續，無有間斷，身、語、意業無有疲厭。善男子！是為菩薩摩訶薩十種大願具足圓滿。若諸菩薩於此大願隨順趣入，則能成熟一切眾生，則能隨順阿耨多羅三藐三菩提，則能成滿普賢菩薩諸行願海。是故，善男子！汝於此義應如是知：若有善男子、善女人以滿十方無量無邊、不可說不可說佛剎極微塵數一切世界上妙七寶，及諸人天最勝安樂，布施爾所一切世界所有眾生，供養爾所一切世界諸佛菩薩，經爾所佛剎極微塵數劫相續不斷所得功德，若復有人聞此願王一經於耳，所有功德比前功德百分不及一，千分不及一，乃至優波尼沙陀分亦不及一。或復有人以深信心，於此大願受持讀誦，乃至書寫一四句偈，速能除滅五無間業，所有世間身心等病，種種苦惱，乃至佛剎極微塵數一切惡業，皆得銷除；一切魔軍、夜叉、羅剎、若鳩槃荼、若毘舍闍、若部多等飲血噉肉諸惡鬼神，皆悉遠離，或時發心親近守護。是故若人誦此願者，行於世間無有障礙，如空中月出於雲翳，諸佛菩薩之所稱讚，一切人天皆應禮敬，一切眾生悉應供養。此善男子善得人身，圓滿普賢所有功德，不久當如普賢菩薩，速得成就微妙色身，具三十二大丈夫相，若生人天，所在之處常居勝族，悉能破壞一切惡趣，悉能遠離一切惡友，悉能制伏一切外道，悉能解脫一切煩惱，如師子王摧伏群獸，堪受一切眾生供養。又復，是人臨命終時，最後剎那一切諸根悉皆散壞，一切親屬悉皆捨離，一切威勢悉皆退失，輔相、大臣、宮城內外，象馬車乘，珍寶伏藏，如是一切無復相隨，唯此願王不相捨離，於一切時引導其前。一剎那中即得往生極樂世界，到已即見阿彌陀佛、文殊師利菩薩、普賢菩薩、觀自在菩薩、彌勒菩薩等，此諸菩薩色相端嚴，功德具足，所共圍遶。其人自見生蓮華中，蒙佛授記；得授記已，經於無數百千萬億那由他劫，普於十方不可說不可說世界，以智慧力隨眾生心而為利益。不久當坐菩提道場，降伏魔軍，成等正覺，轉妙法輪。能令佛剎極微塵數世界眾生發菩提心，隨其根性，教化成熟，乃至盡於未來劫海，廣能利益一切眾生。善男子！彼諸眾生若聞、若信此大願王，受持讀誦，廣為人說，所有功德，除佛世尊餘無知者。是故汝等聞此願王，莫生疑念，應當諦受，受已能讀，讀已能誦，誦已能持，乃至書寫，廣為人說。是諸人等於一念中，所有行願皆得成就，所獲福聚無量無邊。能於煩惱大苦海中拔濟眾生，令其出離，皆得往生阿彌陀佛極樂世界。」', '已發布'),
  (17, '佛說三歸五戒慈心厭離功德經', null, '聞如是：一時，佛在舍衛國祇樹給孤獨園。佛為阿那邠邸長者說：「過去久遠，有梵志名毗羅摩，饒財多寶。若布施時，用八萬四千金鉢盛滿碎銀，八萬四千銀鉢盛滿碎金，復以八萬四千金銀澡罐，復以八萬四千牛皆以金銀覆角，復以八萬四千玉女莊嚴具足，復以八萬四千臥具眾綵自覆，復以八萬四千衣裳，復以八萬四千象馬皆以金銀鞍勒，復以八萬四千房舍布施；復於四城門中布施，隨其所欲皆悉與之；復以一房舍施招提僧。如上施福，不如受三自歸。所以然者，受三歸者，施一切眾生無畏。是故歸佛、法、僧，其福不可計量也。
「如上布施及受三歸福，復不如受五戒福。受五戒者，功德滿具，其福勝也。如上布施及受三歸、五戒福，復不如彈指頃慈念眾生福也。如上布施，及受三歸、五戒，慈念眾生福，復不如起一切世間不可樂想福。所以然者，起一切世間不可樂想福，能令行者滅生死苦，終成佛道，故其福最勝也。」
爾時長者聞佛所說，歡喜奉行。', '已發布'),
  (18, '般若波羅蜜多心經', '唐三藏法師玄奘奉詔譯', '觀自在菩薩，行深般若波羅蜜多時，照見五蘊皆空，度一切苦厄。
舍利子，色不異空，空不異色，色即是空，空即是色，受想行識，亦復如是。
舍利子，是諸法空相，不生不滅，不垢不淨，不增不減。
是故空中無色，無受想行識，無眼耳鼻舌身意，無色聲香味觸法，
無眼界，乃至無意識界，無無明，亦無無明盡，乃至無老死，亦無老死盡。
無苦集滅道，無智亦無得，以無所得故，菩提薩埵，依般若波羅蜜多故，
心無罣礙，無罣礙故，無有恐怖，遠離顛倒夢想，究竟涅槃。
三世諸佛，依般若波羅蜜多故，得阿耨多羅三藐三菩提。
故知般若波羅蜜多，是大神咒，是大明咒，是無上咒，是無等等咒，
能除一切苦，真實不虛。故說般若波羅蜜多咒，即說咒曰：
揭帝揭帝，般羅揭帝，般羅僧揭帝，菩提僧莎訶。', '已發布')
on conflict (seq) do update set
  title = excluded.title,
  translator = excluded.translator,
  content = excluded.content,
  status = excluded.status;

notify pgrst, 'reload schema';
